	["Components.Button"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local ComponentBase = Require("Components.ComponentBase")
	local ComponentUI = Require("Components.ComponentUI")
	local Button = {}
	Button.__index = Button

	function Button.new(section, options)
		options = options or {}
		local root, title, description = ComponentUI.Card(section, options, options.Description and 58 or 46)
		title.Size = UDim2.new(1, -66, 1, options.Description and -18 or 0)
		local arrow = UI.Text(">", 17, Enum.Font.GothamBold)
		arrow.AnchorPoint = Vector2.new(1, 0.5)
		arrow.Position = UDim2.new(1, -14, 0.5, 0)
		arrow.Size = UDim2.fromOffset(20, 24)
		arrow.TextXAlignment = Enum.TextXAlignment.Center
		arrow.Parent = root
		section.Library.ThemeManager:Bind(arrow, { TextColor3 = "AccentAlt" })

		local hitbox = UI.Button("")
		hitbox.Size = UDim2.fromScale(1, 1)
		hitbox.Parent = root

		local base = ComponentUI.AttachBase(ComponentBase.new(section, options, root), title, description)
		base:_Commit(options.Default or 0, true)
		local self = ComponentUI.CopyBaseMethods(setmetatable({}, Button), base)
		self.Hitbox = hitbox

		base.Cleanup:Add(hitbox.MouseEnter:Connect(function()
			section.Library.AnimationManager:Play(root, {
				BackgroundColor3 = section.Library.ThemeManager.Current.SurfaceHover,
			}, 0.14)
		end))
		base.Cleanup:Add(hitbox.MouseLeave:Connect(function()
			section.Library.AnimationManager:Play(root, {
				BackgroundColor3 = section.Library.ThemeManager.Current.SurfaceAlt,
			}, 0.14)
		end))
		base.Cleanup:Add(hitbox.MouseButton1Click:Connect(function()
			self:Press()
		end))
		return self
	end

	function Button:Press()
		local nextValue = (tonumber(self._base.Value) or 0) + 1
		self._base:_Commit(nextValue, false)
		self._base.Library.AnimationManager:Play(self.Root, {
			BackgroundColor3 = self._base.Library.ThemeManager.Current.Accent,
		}, 0.08)
		task.delay(0.09, function()
			if self.Root and self.Root.Parent then
				self._base.Library.AnimationManager:Play(self.Root, {
					BackgroundColor3 = self._base.Library.ThemeManager.Current.SurfaceAlt,
				}, 0.16)
			end
		end)
		return self
	end

	function Button:SetValue(value, silent)
		if value == true or value == "Press" then
			if silent then
				self._base:_Commit((tonumber(self._base.Value) or 0) + 1, true)
			else
				self:Press()
			end
		else
			self._base:_Commit(value, silent)
		end
		return self
	end

	return Button
end
]],
	["Components.ColorPicker"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local ComponentBase = Require("Components.ComponentBase")
	local ComponentUI = Require("Components.ComponentUI")
	local UserInputService = game:GetService("UserInputService")
	local ColorPicker = {}
	ColorPicker.__index = ColorPicker

	local function fromHex(hex)
		hex = string.gsub(tostring(hex or ""), "#", "")
		if #hex ~= 6 then
			return nil
		end
		local r = tonumber(string.sub(hex, 1, 2), 16)
		local g = tonumber(string.sub(hex, 3, 4), 16)
		local b = tonumber(string.sub(hex, 5, 6), 16)
		if not r or not g or not b then
			return nil
		end
		return Color3.fromRGB(r, g, b)
	end

	local function toHex(color)
		return string.format(
			"#%02X%02X%02X",
			math.floor(color.R * 255 + 0.5),
			math.floor(color.G * 255 + 0.5),
			math.floor(color.B * 255 + 0.5)
		)
	end

	function ColorPicker.new(section, options)
		options = options or {}
		local collapsedHeight = options.Description and 58 or 46
		local root, title, description = ComponentUI.Card(section, options, collapsedHeight)
		root.ClipsDescendants = true
		title.Size = UDim2.new(1, -122, title.Size.Y.Scale, title.Size.Y.Offset)

		local preview = UI.Create("TextButton", {
			AnchorPoint = Vector2.new(1, 0.5),
			AutoButtonColor = false,
			BackgroundColor3 = Color3.new(1, 1, 1),
			BorderSizePixel = 0,
			Font = Enum.Font.GothamMedium,
			Position = UDim2.new(1, -12, 0.5, 0),
			Size = UDim2.fromOffset(92, 28),
			Text = "#FFFFFF",
			TextColor3 = Color3.new(0, 0, 0),
			TextSize = 11,
			Parent = root,
		}, {
			UI.Corner(6),
			UI.Stroke(Color3.new(1, 1, 1), 0.55),
		})

		local controls = UI.Create("Frame", {
			Position = UDim2.fromOffset(12, collapsedHeight + 4),
			Size = UDim2.new(1, -24, 0, 96),
			BackgroundTransparency = 1,
			Parent = root,
		})

		local base = ComponentUI.AttachBase(ComponentBase.new(section, options, root), title, description)
		local self = ComponentUI.CopyBaseMethods(setmetatable({}, ColorPicker), base)
		self.Preview = preview
		self.Controls = controls
		self.Open = false
		self.Hue = 0
		self.Saturation = 1
		self.Value = 1
		self.Bars = {}
		self.ApplyAccent = options.ApplyAccent == true

		local function makeBar(name, y, gradient)
			local label = UI.Text(name, 11, Enum.Font.GothamMedium)
			label.Position = UDim2.fromOffset(0, y)
			label.Size = UDim2.fromOffset(18, 22)
			label.Parent = controls
			section.Library.ThemeManager:Bind(label, { TextColor3 = "MutedText" })

			local bar = UI.Create("TextButton", {
				AutoButtonColor = false,
				BackgroundColor3 = Color3.new(1, 1, 1),
				BorderSizePixel = 0,
				Position = UDim2.fromOffset(24, y + 7),
				Size = UDim2.new(1, -24, 0, 9),
				Text = "",
				Parent = controls,
			}, {
				UI.Corner(5),
				UI.Create("UIGradient", {
					Color = gradient,
				}),
			})
			local cursor = UI.Create("Frame", {
				AnchorPoint = Vector2.new(0.5, 0.5),
				Position = UDim2.new(0, 0, 0.5, 0),
				Size = UDim2.fromOffset(13, 13),
				BackgroundColor3 = Color3.new(1, 1, 1),
				BorderSizePixel = 0,
				Parent = bar,
			}, {
				UI.Corner(7),
				UI.Stroke(Color3.fromRGB(30, 30, 35), 0, 1),
			})
			self.Bars[name] = { Bar = bar, Cursor = cursor }
			return bar
		end

		local hueGradient = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Color3.fromHSV(0, 1, 1)),
			ColorSequenceKeypoint.new(0.17, Color3.fromHSV(0.17, 1, 1)),
			ColorSequenceKeypoint.new(0.33, Color3.fromHSV(0.33, 1, 1)),
			ColorSequenceKeypoint.new(0.5, Color3.fromHSV(0.5, 1, 1)),
			ColorSequenceKeypoint.new(0.67, Color3.fromHSV(0.67, 1, 1)),
			ColorSequenceKeypoint.new(0.83, Color3.fromHSV(0.83, 1, 1)),
			ColorSequenceKeypoint.new(1, Color3.fromHSV(1, 1, 1)),
		})
		local hueBar = makeBar("H", 0, hueGradient)
		local saturationBar = makeBar("S", 31, ColorSequence.new(Color3.new(1, 1, 1), Color3.fromHSV(0, 1, 1)))
		local valueBar = makeBar("V", 62, ColorSequence.new(Color3.new(0, 0, 0), Color3.fromHSV(0, 1, 1)))

		local dragging
		local function updateFromInput(input)
			if not dragging then
				return
			end
			local bar = dragging.Bar
			local alpha = math.clamp((input.Position.X - bar.AbsolutePosition.X) / math.max(bar.AbsoluteSize.X, 1), 0, 1)
			if dragging.Name == "H" then
				self.Hue = alpha
			elseif dragging.Name == "S" then
				self.Saturation = alpha
			else
				self.Value = alpha
			end
			self:SetValue(Color3.fromHSV(self.Hue, self.Saturation, self.Value))
		end

		for name, data in pairs(self.Bars) do
			base.Cleanup:Add(data.Bar.InputBegan:Connect(function(input)
				if input.UserInputType == Enum.UserInputType.MouseButton1
					or input.UserInputType == Enum.UserInputType.Touch then
					dragging = { Name = name, Bar = data.Bar }
					updateFromInput(input)
				end
			end))
		end
		base.Cleanup:Add(UserInputService.InputChanged:Connect(function(input)
			if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch) then
				updateFromInput(input)
			end
		end))
		base.Cleanup:Add(UserInputService.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.Touch then
				dragging = nil
			end
		end))
		base.Cleanup:Add(preview.MouseButton1Click:Connect(function()
			self:SetOpen(not self.Open)
		end))

		self.HueBar = hueBar
		self.SaturationBar = saturationBar
		self.ValueBar = valueBar
		self:SetValue(options.Default or Color3.fromRGB(71, 137, 255), true)
		return self
	end

	function ColorPicker:SetOpen(open)
		self.Open = open == true
		local collapsedHeight = self.Options.Description and 58 or 46
		self._base.Library.AnimationManager:Play(self.Root, {
			Size = UDim2.new(1, 0, 0, collapsedHeight + (self.Open and 108 or 0)),
		}, 0.2)
		return self
	end

	function ColorPicker:SetValue(value, silent)
		if type(value) == "string" then
			value = fromHex(value)
		end
		if typeof(value) ~= "Color3" then
			return self
		end
		self.Hue, self.Saturation, self.Value = Color3.toHSV(value)
		self._base:_Commit(value, silent)
		if self.ApplyAccent and not silent then
			self._base.Library:SetAccent(value)
		end
		self.Preview.BackgroundColor3 = value
		self.Preview.Text = toHex(value)
		local luminance = value.R * 0.299 + value.G * 0.587 + value.B * 0.114
		self.Preview.TextColor3 = luminance > 0.58 and Color3.new(0, 0, 0) or Color3.new(1, 1, 1)
		self.Bars.H.Cursor.Position = UDim2.new(self.Hue, 0, 0.5, 0)
		self.Bars.S.Cursor.Position = UDim2.new(self.Saturation, 0, 0.5, 0)
		self.Bars.V.Cursor.Position = UDim2.new(self.Value, 0, 0.5, 0)
		self.SaturationBar.UIGradient.Color = ColorSequence.new(
			Color3.new(1, 1, 1),
			Color3.fromHSV(self.Hue, 1, 1)
		)
		self.ValueBar.UIGradient.Color = ColorSequence.new(
			Color3.new(0, 0, 0),
			Color3.fromHSV(self.Hue, self.Saturation, 1)
		)
		return self
	end

	function ColorPicker:GetHex()
		return toHex(self._base.Value)
	end

	return ColorPicker
end
]],
	["Components.ComponentBase"] = [[
return function(Require)
	local Signal = Require("Utils.Signals")
	local CleanupManager = Require("Managers.CleanupManager")
	local ComponentBase = {}
	ComponentBase.__index = ComponentBase

	function ComponentBase.new(section, options, root)
		options = options or {}
		local self = setmetatable({
			Library = section.Library,
			Section = section,
			Options = options,
			Root = root,
			Title = options.Title or options.Name or "",
			Description = options.Description or "",
			Value = options.Default,
			Flag = options.Flag,
			Visible = options.Visible ~= false,
			SearchVisible = true,
			Destroyed = false,
			Changed = Signal.new(),
			Cleanup = CleanupManager.new(),
		}, ComponentBase)

		if self.Flag then
			self.Library.FlagManager:Register(self.Flag, self)
		end
		self:_BindTooltip()
		self:_BindConditions()
		return self
	end

	function ComponentBase:_BindTooltip()
		local tooltip = self.Options.Tooltip
		if not tooltip or tooltip == "" then
			return
		end
		self.Cleanup:Add(self.Root.MouseEnter:Connect(function()
			self.Library:_ShowTooltip(tostring(tooltip), self.Root)
		end))
		self.Cleanup:Add(self.Root.MouseLeave:Connect(function()
			self.Library:_HideTooltip()
		end))
	end

	function ComponentBase:_BindConditions()
		local dependency = self.Options.DependsOn
		if type(dependency) == "table" then
			local component = dependency.Component
			if component and component.Changed then
				self.Cleanup:Add(component.Changed:Connect(function()
					self:_RefreshVisibility()
				end))
			elseif dependency.Flag then
				self.Cleanup:Add(self.Library.FlagManager.Changed:Connect(function(flag)
					if flag == dependency.Flag then
						self:_RefreshVisibility()
					end
				end))
			end
		end
		self:_RefreshVisibility()
	end

	function ComponentBase:_ConditionPasses()
		local visibleWhen = self.Options.VisibleWhen
		if type(visibleWhen) == "function" then
			local ok, result = pcall(visibleWhen, self.Library.FlagManager:Export(), self)
			return ok and result ~= false
		end

		local dependency = self.Options.DependsOn
		if type(dependency) ~= "table" then
			return true
		end
		local value
		if dependency.Component and dependency.Component.GetValue then
			value = dependency.Component:GetValue()
		elseif dependency.Flag then
			value = self.Library.FlagManager:Get(dependency.Flag)
		end
		if dependency.Predicate then
			local ok, result = pcall(dependency.Predicate, value)
			return ok and result ~= false
		end
		if dependency.Value ~= nil then
			return value == dependency.Value
		end
		return value == true
	end

	function ComponentBase:_RefreshVisibility()
		if self.Root then
			self.Root.Visible = self.Visible and self.SearchVisible and self:_ConditionPasses()
		end
	end

	function ComponentBase:_SetSearchVisible(visible)
		self.SearchVisible = visible == true
		self:_RefreshVisibility()
	end

	function ComponentBase:_Commit(value, silent)
		local previous = self.Value
		self.Value = value
		if self.Flag then
			self.Library.FlagManager:Update(self.Flag, value, self)
		end
		if previous ~= value then
			self.Changed:Fire(value, previous)
		end
		if not silent then
			local callback = self.Options.Callback
			if type(callback) == "function" then
				task.spawn(function()
					local ok, err = xpcall(function()
						callback(value, previous, self)
					end, debug.traceback)
					if not ok then
						warn("[Astra UI] Component callback failed:", err)
					end
				end)
			end
		end
		return value
	end

	function ComponentBase:GetValue()
		return self.Value
	end

	function ComponentBase:SetValue(value, silent)
		return self:_Commit(value, silent)
	end

	function ComponentBase:SetTitle(title)
		self.Title = tostring(title or "")
		if self.TitleLabel then
			self.TitleLabel.Text = self.Title
		end
		return self
	end

	function ComponentBase:SetDescription(description)
		local hadDescription = self.Description ~= ""
		self.Description = tostring(description or "")
		self.Options.Description = self.Description
		if self.DescriptionLabel then
			self.DescriptionLabel.Text = self.Description
			self.DescriptionLabel.Visible = self.Description ~= ""
			local hasDescription = self.Description ~= ""
			if self.TitleLabel then
				self.TitleLabel.Position = UDim2.fromOffset(13, hasDescription and 7 or 0)
				self.TitleLabel.Size = UDim2.new(
					self.TitleLabel.Size.X.Scale,
					self.TitleLabel.Size.X.Offset,
					0,
					hasDescription and 20 or math.max(self.Root.Size.Y.Offset, 20)
				)
			end
			if hadDescription ~= hasDescription and self.Root then
				local delta = hasDescription and 12 or -12
				self.Root.Size = UDim2.new(
					self.Root.Size.X.Scale,
					self.Root.Size.X.Offset,
					self.Root.Size.Y.Scale,
					math.max(24, self.Root.Size.Y.Offset + delta)
				)
			end
		end
		return self
	end

	function ComponentBase:SetVisible(visible)
		self.Visible = visible == true
		self:_RefreshVisibility()
		return self
	end

	function ComponentBase:Hide()
		return self:SetVisible(false)
	end

	function ComponentBase:Show()
		return self:SetVisible(true)
	end

	function ComponentBase:Destroy()
		if self.Destroyed then
			return
		end
		self.Destroyed = true
		if self.Flag then
			self.Library.FlagManager:Unregister(self.Flag, self)
		end
		self.Changed:Destroy()
		self.Cleanup:Destroy()
		if self.Root then
			self.Root:Destroy()
			self.Root = nil
		end
	end

	return ComponentBase
end
]],
	["Components.ComponentUI"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local ComponentUI = {}

	function ComponentUI.Card(section, options, height)
		local library = section.Library
		local root = UI.Create("Frame", {
			Name = (options.Title or options.Name or "Component") .. "Component",
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			LayoutOrder = section:_NextOrder(),
			Size = UDim2.new(1, 0, 0, height or 48),
			Parent = section.Content,
		}, {
			UI.Corner(9),
			UI.Stroke(),
		})
		library.ThemeManager:Bind(root, {
			BackgroundColor3 = "SurfaceAlt",
		})
		library.ThemeManager:Bind(root:FindFirstChildOfClass("UIStroke"), {
			Color = "Border",
		})

		local title = UI.Text(options.Title or options.Name or "", 14, Enum.Font.GothamSemibold)
		title.Name = "Title"
		title.Position = UDim2.fromOffset(13, options.Description and 7 or 0)
		title.Size = UDim2.new(1, -26, 0, options.Description and 20 or height or 48)
		title.Parent = root
		library.ThemeManager:Bind(title, {
			TextColor3 = "Text",
		})

		local description = UI.Text(options.Description or "", 12, Enum.Font.Gotham)
		description.Name = "Description"
		description.Position = UDim2.fromOffset(13, 26)
		description.Size = UDim2.new(1, -26, 0, 18)
		description.Visible = options.Description ~= nil and options.Description ~= ""
		description.Parent = root
		library.ThemeManager:Bind(description, {
			TextColor3 = "MutedText",
		})

		return root, title, description
	end

	function ComponentUI.AttachBase(base, title, description)
		base.TitleLabel = title
		base.DescriptionLabel = description
		return base
	end

	function ComponentUI.CopyBaseMethods(target, base)
		target._base = base
		target.Options = base.Options
		target.Library = base.Library
		target.Section = base.Section
		target.Title = base.Title
		target.Description = base.Description
		target.Flag = base.Flag
		for _, method in ipairs({
			"GetValue",
			"SetTitle",
			"SetDescription",
			"SetVisible",
			"Hide",
			"Show",
			"Destroy",
		}) do
			target[method] = function(self, ...)
				return base[method](base, ...)
			end
		end
		target.Changed = base.Changed
		target.Root = base.Root
		return target
	end

	return ComponentUI
end
]],
	["Components.Dialog"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local Signal = Require("Utils.Signals")
	local CleanupManager = Require("Managers.CleanupManager")
	local Dialog = {}
	Dialog.__index = Dialog

	function Dialog.new(library, options)
		options = options or {}
		local overlay = UI.Create("CanvasGroup", {
			BackgroundColor3 = Color3.new(0, 0, 0),
			BackgroundTransparency = 0.38,
			BorderSizePixel = 0,
			GroupTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			Parent = library.ModalLayer,
		})
		local panel = UI.Create("Frame", {
			AnchorPoint = Vector2.new(0.5, 0.5),
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = UDim2.fromScale(0.5, 0.5),
			Size = options.Size or UDim2.fromOffset(390, 210),
			Parent = overlay,
		}, {
			UI.Corner(12),
			UI.Stroke(),
		})
		library.ThemeManager:Bind(panel, { BackgroundColor3 = "Surface" })
		library.ThemeManager:Bind(panel:FindFirstChildOfClass("UIStroke"), { Color = "Border" })

		local title = UI.Text(options.Title or "Confirm", 18, Enum.Font.GothamBold)
		title.Position = UDim2.fromOffset(20, 17)
		title.Size = UDim2.new(1, -40, 0, 28)
		title.Parent = panel
		library.ThemeManager:Bind(title, { TextColor3 = "Text" })

		local content = UI.Text(options.Content or "", 13, Enum.Font.Gotham)
		content.Position = UDim2.fromOffset(20, 54)
		content.Size = UDim2.new(1, -40, 1, -118)
		content.TextYAlignment = Enum.TextYAlignment.Top
		content.Parent = panel
		library.ThemeManager:Bind(content, { TextColor3 = "MutedText" })

		local buttonHolder = UI.Create("Frame", {
			AnchorPoint = Vector2.new(0, 1),
			BackgroundTransparency = 1,
			Position = UDim2.new(0, 20, 1, -18),
			Size = UDim2.new(1, -40, 0, 38),
			Parent = panel,
		}, {
			UI.Create("UIListLayout", {
				FillDirection = Enum.FillDirection.Horizontal,
				HorizontalAlignment = Enum.HorizontalAlignment.Right,
				Padding = UDim.new(0, 8),
				SortOrder = Enum.SortOrder.LayoutOrder,
			}),
		})

		local self = setmetatable({
			Library = library,
			Root = overlay,
			Panel = panel,
			TitleLabel = title,
			ContentLabel = content,
			Value = nil,
			Visible = true,
			Changed = Signal.new(),
			Cleanup = CleanupManager.new(),
			Closed = false,
		}, Dialog)

		for index, buttonOptions in ipairs(options.Buttons or {
			{ Title = "Cancel", Value = false },
			{ Title = "Confirm", Value = true, Primary = true },
		}) do
			local button = UI.Create("TextButton", {
				AutoButtonColor = false,
				BackgroundTransparency = 0,
				BorderSizePixel = 0,
				Font = Enum.Font.GothamSemibold,
				LayoutOrder = index,
				Size = UDim2.fromOffset(104, 38),
				Text = buttonOptions.Title or "Button",
				TextSize = 13,
				Parent = buttonHolder,
			}, {
				UI.Corner(7),
				UI.Stroke(),
			})
			library.ThemeManager:Bind(button, {
				BackgroundColor3 = buttonOptions.Primary and "Accent" or "SurfaceAlt",
				TextColor3 = "Text",
			})
			library.ThemeManager:Bind(button:FindFirstChildOfClass("UIStroke"), { Color = "Border" })
			self.Cleanup:Add(button.MouseButton1Click:Connect(function()
				self:SetValue(buttonOptions.Value ~= nil and buttonOptions.Value or buttonOptions.Title)
				if buttonOptions.Callback then
					task.spawn(buttonOptions.Callback, self.Value, self)
				end
				if options.Callback then
					task.spawn(options.Callback, self.Value, self)
				end
				self:Destroy()
			end))
		end

		library.AnimationManager:Play(overlay, { GroupTransparency = 0 }, 0.2)
		library.AnimationManager:Play(panel, { Size = panel.Size }, 0.22, Enum.EasingStyle.Back)
		return self
	end

	function Dialog:SetValue(value)
		local previous = self.Value
		self.Value = value
		self.Changed:Fire(value, previous)
		return self
	end

	function Dialog:GetValue()
		return self.Value
	end

	function Dialog:SetTitle(title)
		self.TitleLabel.Text = tostring(title or "")
		return self
	end

	function Dialog:SetDescription(description)
		self.ContentLabel.Text = tostring(description or "")
		return self
	end

	function Dialog:Show()
		self.Visible = true
		self.Root.Visible = true
		self.Library.AnimationManager:Play(self.Root, { GroupTransparency = 0 }, 0.18)
		return self
	end

	function Dialog:Hide()
		self.Visible = false
		self.Root.Visible = false
		return self
	end

	function Dialog:SetVisible(visible)
		return visible and self:Show() or self:Hide()
	end

	function Dialog:Destroy()
		if self.Closed then
			return
		end
		self.Closed = true
		self.Cleanup:Destroy()
		self.Changed:Destroy()
		if self.Root then
			self.Root:Destroy()
			self.Root = nil
		end
	end

	return Dialog
end
