	["Components.Keybind"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local ComponentBase = Require("Components.ComponentBase")
	local ComponentUI = Require("Components.ComponentUI")
	local UserInputService = game:GetService("UserInputService")
	local Keybind = {}
	Keybind.__index = Keybind

	local function normalize(value)
		if typeof(value) == "EnumItem" then
			return value
		end
		if type(value) == "string" then
			return Enum.KeyCode[value] or Enum.UserInputType[value]
		end
		return Enum.KeyCode.Unknown
	end

	function Keybind.new(section, options)
		options = options or {}
		local root, title, description = ComponentUI.Card(section, options, options.Description and 58 or 46)
		title.Size = UDim2.new(1, -120, title.Size.Y.Scale, title.Size.Y.Offset)
		local capture = UI.Create("TextButton", {
			AnchorPoint = Vector2.new(1, 0.5),
			AutoButtonColor = false,
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Font = Enum.Font.GothamMedium,
			Position = UDim2.new(1, -12, 0.5, 0),
			Size = UDim2.fromOffset(88, 28),
			Text = "",
			TextSize = 12,
			Parent = root,
		}, {
			UI.Corner(6),
			UI.Stroke(),
		})
		section.Library.ThemeManager:Bind(capture, {
			BackgroundColor3 = "Surface",
			TextColor3 = "AccentAlt",
		})
		section.Library.ThemeManager:Bind(capture:FindFirstChildOfClass("UIStroke"), { Color = "Border" })

		local base = ComponentUI.AttachBase(ComponentBase.new(section, options, root), title, description)
		local self = ComponentUI.CopyBaseMethods(setmetatable({}, Keybind), base)
		self.Capture = capture
		self.Listening = false
		self.Active = false

		base.Cleanup:Add(capture.MouseButton1Click:Connect(function()
			self.Listening = true
			capture.Text = "Press a key"
		end))
		base.Cleanup:Add(UserInputService.InputBegan:Connect(function(input, processed)
			if self.Listening then
				local key = input.KeyCode ~= Enum.KeyCode.Unknown and input.KeyCode or input.UserInputType
				self.Listening = false
				self:SetValue(key)
				return
			end
			if processed and not options.IgnoreProcessed then
				return
			end
			local matches = input.KeyCode == base.Value or input.UserInputType == base.Value
			if matches then
				if options.Mode == "Toggle" then
					self.Active = not self.Active
					if options.OnToggle then
						task.spawn(options.OnToggle, self.Active)
					end
				end
				if options.OnPressed then
					task.spawn(options.OnPressed, self.Active, input)
				elseif options.Callback then
					task.spawn(options.Callback, base.Value, self.Active, input)
				end
			end
		end))
		self:SetValue(options.Default or Enum.KeyCode.RightShift, true)
		return self
	end

	function Keybind:SetValue(value, silent)
		value = normalize(value)
		self._base:_Commit(value, silent)
		self.Capture.Text = value.Name
		return self
	end

	return Keybind
end
]],
	["Components.Notification"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local Signal = Require("Utils.Signals")
	local CleanupManager = Require("Managers.CleanupManager")
	local Notification = {}
	Notification.__index = Notification

	function Notification.new(library, options)
		options = options or {}
		local typeName = options.Type or "Info"
		local colorToken = typeName == "Success" and "Success"
			or typeName == "Error" and "Error"
			or typeName == "Warning" and "Warning"
			or "Accent"

		local root = UI.Create("CanvasGroup", {
			AnchorPoint = Vector2.new(1, 0),
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			GroupTransparency = 1,
			Size = UDim2.fromOffset(330, 86),
			Parent = library.NotificationContainer,
		}, {
			UI.Corner(10),
			UI.Stroke(),
		})
		library.ThemeManager:Bind(root, { BackgroundColor3 = "Surface" })
		library.ThemeManager:Bind(root:FindFirstChildOfClass("UIStroke"), { Color = "Border" })

		local accent = UI.Create("Frame", {
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Size = UDim2.fromOffset(4, 86),
			Parent = root,
		}, { UI.Corner(4) })
		library.ThemeManager:Bind(accent, { BackgroundColor3 = colorToken })

		local title = UI.Text(options.Title or typeName, 14, Enum.Font.GothamSemibold)
		title.Position = UDim2.fromOffset(17, 10)
		title.Size = UDim2.new(1, -52, 0, 22)
		title.Parent = root
		library.ThemeManager:Bind(title, { TextColor3 = "Text" })

		local content = UI.Text(options.Content or options.Text or "", 12, Enum.Font.Gotham)
		content.Position = UDim2.fromOffset(17, 34)
		content.Size = UDim2.new(1, -34, 0, 39)
		content.TextYAlignment = Enum.TextYAlignment.Top
		content.Parent = root
		library.ThemeManager:Bind(content, { TextColor3 = "MutedText" })

		local self = setmetatable({
			Library = library,
			Root = root,
			TitleLabel = title,
			ContentLabel = content,
			Value = options.Content or options.Text or "",
			Visible = true,
			Changed = Signal.new(),
			Cleanup = CleanupManager.new(),
			Closed = false,
		}, Notification)

		local close = UI.Button("X")
		close.AnchorPoint = Vector2.new(1, 0)
		close.Position = UDim2.new(1, -8, 0, 8)
		close.Size = UDim2.fromOffset(24, 24)
		close.TextSize = 12
		close.Parent = root
		library.ThemeManager:Bind(close, { TextColor3 = "MutedText" })
		self.Cleanup:Add(close.MouseButton1Click:Connect(function()
			self:Destroy()
		end))
		return self
	end

	function Notification:Show()
		self.Visible = true
		self.Root.Visible = true
		self.Library.AnimationManager:Play(self.Root, { GroupTransparency = 0 }, 0.22)
		return self
	end

	function Notification:Hide()
		self.Visible = false
		self.Library.AnimationManager:Play(self.Root, { GroupTransparency = 1 }, 0.18)
		task.delay(0.2, function()
			if self.Root and self.Root.Parent and not self.Visible then
				self.Root.Visible = false
			end
		end)
		return self
	end

	function Notification:SetVisible(visible)
		return visible and self:Show() or self:Hide()
	end

	function Notification:SetValue(value)
		local previous = self.Value
		self.Value = tostring(value or "")
		self.ContentLabel.Text = self.Value
		self.Changed:Fire(self.Value, previous)
		return self
	end

	function Notification:GetValue()
		return self.Value
	end

	function Notification:SetTitle(title)
		self.TitleLabel.Text = tostring(title or "")
		return self
	end

	function Notification:SetDescription(description)
		return self:SetValue(description)
	end

	function Notification:Destroy()
		if self.Closed then
			return
		end
		self.Closed = true
		self.Cleanup:Destroy()
		self.Changed:Destroy()
		if self.Root then
			self.Root:Destroy()
			self.Root = nil
		end
		self.Library:_AdvanceNotifications()
	end

	return Notification
end
]],
