	["Library"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local Blur = Require("Utils.Blur")
	local Responsive = Require("Utils.Responsive")
	local ExecutorDetection = Require("Utils.ExecutorDetection")
	local CleanupManager = Require("Managers.CleanupManager")
	local EventManager = Require("Managers.EventManager")
	local AnimationManager = Require("Managers.AnimationManager")
	local StateManager = Require("Managers.StateManager")
	local FlagManager = Require("Managers.FlagManager")
	local ThemeManager = Require("Managers.ThemeManager")
	local ConfigManager = Require("Managers.ConfigManager")
	local Window = Require("Window")
	local Notification = Require("Components.Notification")
	local Dialog = Require("Components.Dialog")

	local Players = game:GetService("Players")
	local CoreGui = game:GetService("CoreGui")
	local RunService = game:GetService("RunService")
	local TextService = game:GetService("TextService")
	local UserInputService = game:GetService("UserInputService")

	local Library = {}
	Library.__index = Library
	Library.Version = "1.1.0"

	local function resolveParent(options)
		if options.Parent then
			return options.Parent
		end
		if type(gethui) == "function" then
			local ok, result = pcall(gethui)
			if ok and result then
				return result
			end
		end
		local player = Players.LocalPlayer
		if player then
			local playerGui = player:FindFirstChildOfClass("PlayerGui") or player:WaitForChild("PlayerGui", 5)
			if playerGui then
				return playerGui
			end
		end
		return CoreGui
	end

	function Library.new(options)
		options = options or {}
		local capabilities = ExecutorDetection.Detect()
		local cleanup = CleanupManager.new()
		local themeManager = ThemeManager.new()
		local flagManager = FlagManager.new()
		local eventManager = EventManager.new()
		local animationManager = AnimationManager.new(options.ReducedMotion)
		local stateManager = StateManager.new({
			Visible = true,
			Mode = Responsive.GetMode(),
		})
		local configManager = ConfigManager.new(flagManager, themeManager, capabilities)

		local screenGui = UI.Create("ScreenGui", {
			DisplayOrder = options.DisplayOrder or 999,
			IgnoreGuiInset = true,
			Name = options.Name or ("AstraUI_" .. tostring(math.random(100000, 999999))),
			ResetOnSpawn = false,
			ZIndexBehavior = Enum.ZIndexBehavior.Sibling,
		})
		local parent = resolveParent(options)
		if capabilities.ProtectGui then
			local environment = getgenv and getgenv() or _G
			local protect = type(protectgui) == "function" and protectgui
				or environment.syn and environment.syn.protect_gui
			if protect then
				pcall(protect, screenGui)
			end
		end
		screenGui.Parent = parent

		local root = UI.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.fromScale(1, 1),
			Parent = screenGui,
		})
		local windowLayer = UI.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 1,
			Parent = root,
		})
		local notificationLayer = UI.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 1000,
			Parent = root,
		})
		local notificationContainer = UI.Create("Frame", {
			AnchorPoint = Vector2.new(1, 0),
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Position = UDim2.new(1, -18, 0, 18),
			Size = UDim2.fromOffset(340, 600),
			Parent = notificationLayer,
		}, {
			UI.Create("UIListLayout", {
				HorizontalAlignment = Enum.HorizontalAlignment.Right,
				Padding = UDim.new(0, 9),
				SortOrder = Enum.SortOrder.LayoutOrder,
			}),
		})
		local modalLayer = UI.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 2000,
			Parent = root,
		})
		local overlayLayer = UI.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 3000,
			Parent = root,
		})

		local self = setmetatable({
			Options = options,
			ScreenGui = screenGui,
			Root = root,
			WindowLayer = windowLayer,
			NotificationLayer = notificationLayer,
			NotificationContainer = notificationContainer,
			ModalLayer = modalLayer,
			OverlayLayer = overlayLayer,
			Capabilities = capabilities,
			Mode = Responsive.GetMode(),
			Cleanup = cleanup,
			EventManager = eventManager,
			AnimationManager = animationManager,
			StateManager = stateManager,
			FlagManager = flagManager,
			ThemeManager = themeManager,
			ConfigManager = configManager,
			Flags = flagManager,
			Windows = {},
			Locales = { en = {} },
			Locale = options.Locale or "en",
			NotificationQueue = {},
			ActiveNotifications = {},
			MaxNotifications = options.MaxNotifications or 4,
			BlurUsers = 0,
			Destroyed = false,
			_zIndex = 20,
		}, Library)

		self.Blur = Blur.new(screenGui.Name .. "_Blur")
		cleanup:Add(self.Blur)
		cleanup:Add(screenGui)
		cleanup:Add(eventManager)
		cleanup:Add(stateManager)
		cleanup:Add(flagManager)
		cleanup:Add(configManager)
		cleanup:Add(themeManager)

		local scale, responsiveConnection = Responsive.Attach(root, function(mode, viewport, currentScale)
			self.Mode = mode
			self.StateManager:Set("Mode", mode)
			self.EventManager:Emit("ResponsiveChanged", mode, viewport, currentScale)
			self:_UpdateMobileButton()
		end)
		self.Scale = scale
		if responsiveConnection then
			cleanup:Add(responsiveConnection)
		end

		self:_CreateTooltip()
		self:_CreateMobileButton()
		if options.Theme then
			self:SetTheme(options.Theme)
		end
		if options.ConfigFolder then
			configManager:SetFolder(options.ConfigFolder)
		end
		if options.AutoSave then
			configManager:SetAutoSave(true, options.AutoSaveName or "autosave", options.AutoSaveDelay)
		end
		return self
	end

	function Library:_CreateTooltip()
		local tooltip = UI.Create("CanvasGroup", {
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = UDim2.fromOffset(0, 0),
			Visible = false,
			ZIndex = 3100,
			Parent = self.OverlayLayer,
		}, {
			UI.Corner(6),
			UI.Stroke(),
			UI.Padding(7, 9, 7, 9),
		})
		self.ThemeManager:Bind(tooltip, { BackgroundColor3 = "Surface" })
		self.ThemeManager:Bind(tooltip:FindFirstChildOfClass("UIStroke"), { Color = "Border" })
		local label = UI.Text("", 11, Enum.Font.Gotham)
		label.AutomaticSize = Enum.AutomaticSize.XY
		label.Size = UDim2.fromOffset(0, 0)
		label.ZIndex = 3101
		label.Parent = tooltip
		self.ThemeManager:Bind(label, { TextColor3 = "Text" })
		self.Tooltip = tooltip
		self.TooltipLabel = label
		self.Cleanup:Add(UserInputService.InputChanged:Connect(function(input)
			if tooltip.Visible and (input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch) then
				tooltip.Position = UDim2.fromOffset(input.Position.X + 14, input.Position.Y + 14)
			end
		end))
	end

	function Library:_ShowTooltip(text, anchor)
		self.TooltipLabel.Text = text
		local bounds = TextService:GetTextSize(text, 11, Enum.Font.Gotham, Vector2.new(280, 500))
		self.TooltipLabel.Size = UDim2.fromOffset(math.min(bounds.X, 280), bounds.Y)
		local mouse = UserInputService:GetMouseLocation()
		self.Tooltip.Position = UDim2.fromOffset(mouse.X + 14, mouse.Y + 14)
		self.Tooltip.Visible = true
		self.Tooltip.GroupTransparency = 1
		self.AnimationManager:Play(self.Tooltip, { GroupTransparency = 0 }, 0.12)
	end

	function Library:_HideTooltip()
		if self.Tooltip then
			self.Tooltip.Visible = false
		end
	end

	function Library:_CreateMobileButton()
		local button = UI.Create("TextButton", {
			AnchorPoint = Vector2.new(1, 1),
			AutoButtonColor = false,
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Font = Enum.Font.GothamBold,
			Position = UDim2.new(1, -18, 1, -18),
			Size = UDim2.fromOffset(48, 48),
			Text = "UI",
			TextSize = 13,
			Visible = false,
			ZIndex = 3050,
			Parent = self.OverlayLayer,
		}, {
			UI.Corner(14),
			UI.Stroke(),
		})
		self.ThemeManager:Bind(button, {
			BackgroundColor3 = "Accent",
			TextColor3 = "Text",
		})
		self.ThemeManager:Bind(button:FindFirstChildOfClass("UIStroke"), { Color = "AccentAlt" })
		self.MobileButton = button
		self.Cleanup:Add(button.MouseButton1Click:Connect(function()
			local anyVisible = false
			for _, window in ipairs(self.Windows) do
				anyVisible = anyVisible or window.Visible
			end
			for _, window in ipairs(self.Windows) do
				window:SetVisible(not anyVisible)
			end
		end))
		self:_UpdateMobileButton()
	end

	function Library:_UpdateMobileButton()
		if self.MobileButton then
			self.MobileButton.Visible = self.Mode == "Mobile" or self.Options.AlwaysShowMobileButton == true
		end
	end

	function Library:_AcquireBlur()
		self.BlurUsers = self.BlurUsers + 1
		self.AnimationManager:Play(self.Blur.Effect, {
			Size = self.Options.BlurSize or 14,
		}, 0.2)
	end

	function Library:_ReleaseBlur()
		self.BlurUsers = math.max(0, self.BlurUsers - 1)
		if self.BlurUsers == 0 then
			self.AnimationManager:Play(self.Blur.Effect, { Size = 0 }, 0.2)
		end
	end

	function Library:_FocusWindow(window)
		self._zIndex = self._zIndex + 2
		window.Shadow.ZIndex = self._zIndex
		window.Frame.ZIndex = self._zIndex + 1
	end

	function Library:_RemoveWindow(window)
		local index = table.find(self.Windows, window)
		if index then
			table.remove(self.Windows, index)
		end
	end

	function Library:CreateWindow(options)
		assert(not self.Destroyed, "Cannot create a window on a destroyed library")
		local window = Window.new(self, options)
		table.insert(self.Windows, window)
		self:_FocusWindow(window)
		self.EventManager:Emit("WindowCreated", window)
		return window
	end

	function Library:Notify(options)
		local notification = Notification.new(self, options)
		notification.Root.Visible = false
		table.insert(self.NotificationQueue, {
			Object = notification,
			Duration = math.max(0.25, tonumber(options and options.Duration) or 5),
		})
		self:_AdvanceNotifications()
		return notification
	end

	function Library:_AdvanceNotifications()
		if self.Destroyed then
			return
		end
		local active = {}
		for _, item in ipairs(self.ActiveNotifications) do
			if not item.Object.Closed then
				table.insert(active, item)
			end
		end
		self.ActiveNotifications = active

		while #self.ActiveNotifications < self.MaxNotifications and #self.NotificationQueue > 0 do
			local item = table.remove(self.NotificationQueue, 1)
			if not item.Object.Closed then
				table.insert(self.ActiveNotifications, item)
				item.Object:Show()
				task.delay(item.Duration, function()
					if not item.Object.Closed then
						item.Object:Destroy()
					end
				end)
			end
		end
	end

	function Library:Dialog(options)
		local dialog = Dialog.new(self, options)
		self.Cleanup:Add(dialog)
		return dialog
	end

	function Library:CreateWatermark(options)
		if type(options) == "string" then
			options = { Text = options }
		end
		options = options or {}
		local root = UI.Create("Frame", {
			AutomaticSize = Enum.AutomaticSize.X,
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = options.Position or UDim2.fromOffset(15, 15),
			Size = UDim2.fromOffset(0, 30),
			Parent = self.OverlayLayer,
		}, {
			UI.Corner(7),
			UI.Stroke(),
			UI.Padding(0, 10, 0, 10),
		})
		self.ThemeManager:Bind(root, { BackgroundColor3 = "Surface" })
		self.ThemeManager:Bind(root:FindFirstChildOfClass("UIStroke"), { Color = "Border" })
		local label = UI.Text(options.Text or "Astra UI", 11, Enum.Font.GothamSemibold)
		label.AutomaticSize = Enum.AutomaticSize.X
		label.Size = UDim2.fromOffset(0, 30)
		label.Parent = root
		self.ThemeManager:Bind(label, { TextColor3 = "Text" })

		local watermark = {
			Root = root,
			Label = label,
			BaseText = options.Text or "Astra UI",
			ShowFPS = options.ShowFPS == true,
			Visible = true,
		}
		function watermark:SetText(text)
			self.BaseText = tostring(text or "")
			self.Label.Text = self.BaseText
			return self
		end
		function watermark:SetVisible(visible)
			self.Visible = visible == true
			self.Root.Visible = self.Visible
			return self
		end
		function watermark:Hide()
			return self:SetVisible(false)
		end
		function watermark:Show()
			return self:SetVisible(true)
		end
		function watermark:Destroy()
			if self.Destroyed then
				return
			end
			self.Destroyed = true
			if self.Connection then
				self.Connection:Disconnect()
			end
			if self.Root then
				self.Root:Destroy()
				self.Root = nil
			end
		end

		if watermark.ShowFPS then
			local frames = 0
			local elapsed = 0
			watermark.Connection = RunService.RenderStepped:Connect(function(delta)
				frames = frames + 1
				elapsed = elapsed + delta
				if elapsed >= 0.5 then
					local fps = math.floor(frames / elapsed + 0.5)
					label.Text = watermark.BaseText .. "  |  " .. fps .. " FPS"
					frames = 0
					elapsed = 0
				end
			end)
		end
		self.Cleanup:Add(watermark)
		return watermark
	end

	function Library:RegisterLocale(locale, translations)
		assert(type(locale) == "string", "Locale must be a string")
		assert(type(translations) == "table", "Translations must be a table")
		self.Locales[locale] = table.clone(translations)
		return self
	end

	function Library:SetLocale(locale)
		assert(self.Locales[locale], "Unknown locale: " .. tostring(locale))
		self.Locale = locale
		self.EventManager:Emit("LocaleChanged", locale)
		return self
	end

	function Library:Translate(key, fallback, replacements)
		local text = self.Locales[self.Locale] and self.Locales[self.Locale][key]
			or self.Locales.en[key]
			or fallback
			or key
		for name, value in pairs(replacements or {}) do
			text = string.gsub(text, "{" .. name .. "}", tostring(value))
		end
		return text
	end

	function Library:RegisterTheme(name, theme)
		return self.ThemeManager:Register(name, theme)
	end

	function Library:SetTheme(theme)
		self.ThemeManager:Set(theme)
		self.EventManager:Emit("ThemeChanged", self.ThemeManager.Current, self.ThemeManager.CurrentName)
		return self
	end

	function Library:SetAccent(color)
		self.ThemeManager:SetAccent(color)
		self.EventManager:Emit("ThemeChanged", self.ThemeManager.Current, self.ThemeManager.CurrentName)
		return self
	end

	function Library:GetTheme()
		return self.ThemeManager.Current
	end

	function Library:GetThemes()
		return self.ThemeManager:GetNames()
	end

	function Library:SaveConfig(name)
		return self.ConfigManager:SaveConfig(name)
	end

	function Library:LoadConfig(name, options)
		return self.ConfigManager:LoadConfig(name, options)
	end

	function Library:DeleteConfig(name)
		return self.ConfigManager:DeleteConfig(name)
	end

	function Library:ExportConfig()
		return self.ConfigManager:ExportConfig()
	end

	function Library:ImportConfig(json, options)
		return self.ConfigManager:ImportConfig(json, options)
	end

	function Library:SetVisible(visible)
		visible = visible == true
		self.Root.Visible = visible
		self.StateManager:Set("Visible", visible)
		self.AnimationManager:Play(self.Blur.Effect, {
			Size = visible and self.BlurUsers > 0 and (self.Options.BlurSize or 14) or 0,
		}, 0.18)
		return self
	end

	function Library:Hide()
		return self:SetVisible(false)
	end

	function Library:Show()
		return self:SetVisible(true)
	end

	function Library:Toggle()
		return self:SetVisible(not self.Root.Visible)
	end

	function Library:Destroy()
		if self.Destroyed then
			return
		end
		self.Destroyed = true
		for index = #self.Windows, 1, -1 do
			self.Windows[index]:Destroy()
		end
		for _, item in ipairs(self.ActiveNotifications) do
			if not item.Object.Closed then
				item.Object:Destroy()
			end
		end
		for _, item in ipairs(self.NotificationQueue) do
			if not item.Object.Closed then
				item.Object:Destroy()
			end
		end
		self.Cleanup:Destroy()
	end

	return Library
end
]],
	["Managers.AnimationManager"] = [[
return function(Require)
	local Tween = Require("Utils.Tween")
	local AnimationManager = {}
	AnimationManager.__index = AnimationManager

	function AnimationManager.new(reducedMotion)
		return setmetatable({
			ReducedMotion = reducedMotion == true,
		}, AnimationManager)
	end

	function AnimationManager:SetReducedMotion(enabled)
		self.ReducedMotion = enabled == true
	end

	function AnimationManager:Play(instance, properties, duration, style, direction)
		if self.ReducedMotion then
			for property, value in pairs(properties) do
				instance[property] = value
			end
			return nil
		end
		return Tween.Play(instance, properties, duration, style, direction)
	end

	function AnimationManager:Fade(instance, visible, duration)
		instance.Visible = true
		local goal = visible and 0 or 1
		local tween = self:Play(instance, { GroupTransparency = goal }, duration or 0.18)
		if not visible and tween then
			tween.Completed:Once(function()
				if instance.Parent and instance.GroupTransparency >= 0.99 then
					instance.Visible = false
				end
			end)
		elseif not visible then
			instance.Visible = false
		end
		return tween
	end

	return AnimationManager
end
]],
	["Managers.CleanupManager"] = [[
return function()
	local CleanupManager = {}
	CleanupManager.__index = CleanupManager

	function CleanupManager.new()
		return setmetatable({
			_tasks = {},
			_destroyed = false,
		}, CleanupManager)
	end

	function CleanupManager:Add(taskValue)
		if self._destroyed then
			self:_CleanTask(taskValue)
			return taskValue
		end
		table.insert(self._tasks, taskValue)
		return taskValue
	end

	function CleanupManager:_CleanTask(taskValue)
		local valueType = typeof(taskValue)
		if valueType == "RBXScriptConnection" then
			taskValue:Disconnect()
		elseif valueType == "Instance" then
			taskValue:Destroy()
		elseif type(taskValue) == "function" then
			taskValue()
		elseif type(taskValue) == "thread" then
			task.cancel(taskValue)
		elseif type(taskValue) == "table" then
			if type(taskValue.Destroy) == "function" then
				taskValue:Destroy()
			elseif type(taskValue.Disconnect) == "function" then
				taskValue:Disconnect()
			elseif type(taskValue.Cancel) == "function" then
				taskValue:Cancel()
			end
		end
	end

	function CleanupManager:Remove(taskValue)
		local index = table.find(self._tasks, taskValue)
		if index then
			table.remove(self._tasks, index)
			self:_CleanTask(taskValue)
			return true
		end
		return false
	end

	function CleanupManager:Clean()
		for index = #self._tasks, 1, -1 do
			local taskValue = table.remove(self._tasks, index)
			local ok, err = pcall(function()
				self:_CleanTask(taskValue)
			end)
			if not ok then
				warn("[Astra UI] Cleanup error:", err)
			end
		end
	end

	function CleanupManager:Destroy()
		if self._destroyed then
			return
		end
		self._destroyed = true
		self:Clean()
	end

	return CleanupManager
end
]],
	["Managers.ConfigManager"] = [[
return function(Require)
	local Signal = Require("Utils.Signals")
	local HttpService = game:GetService("HttpService")
	local ConfigManager = {}
	ConfigManager.__index = ConfigManager

	local function encodeValue(value)
		local valueType = typeof(value)
		if valueType == "Color3" then
			return {
				__type = "Color3",
				r = value.R,
				g = value.G,
				b = value.B,
			}
		end
		if valueType == "EnumItem" then
			return {
				__type = "EnumItem",
				enum = tostring(value.EnumType),
				name = value.Name,
			}
		end
		if type(value) == "table" then
			local result = {}
			for key, child in pairs(value) do
				result[key] = encodeValue(child)
			end
			return result
		end
		return value
	end

	local function decodeValue(value)
		if type(value) ~= "table" then
			return value
		end
		if value.__type == "Color3" then
			return Color3.new(value.r, value.g, value.b)
		end
		if value.__type == "EnumItem" then
			local enumName = string.match(value.enum or "", "Enum%.(.+)")
			local enumType = enumName and Enum[enumName]
			return enumType and enumType[value.name] or value.name
		end
		local result = {}
		for key, child in pairs(value) do
			result[key] = decodeValue(child)
		end
		return result
	end

	local function cleanName(name)
		return string.gsub(tostring(name or "default"), "[^%w%-%_]", "_")
	end

	function ConfigManager.new(flagManager, themeManager, capabilities)
		local self = setmetatable({
			Flags = flagManager,
			Themes = themeManager,
			Capabilities = capabilities,
			Folder = "AstraUI",
			Memory = {},
			AutoSave = false,
			AutoSaveName = "autosave",
			AutoSaveDelay = 0.75,
			_pendingAutoSave = nil,
			Saved = Signal.new(),
			Loaded = Signal.new(),
		}, ConfigManager)

		self._flagConnection = flagManager.Changed:Connect(function()
			self:_ScheduleAutoSave()
		end)
		return self
	end

	function ConfigManager:SetFolder(folder)
		self.Folder = cleanName(folder)
		return self
	end

	function ConfigManager:_Path(name)
		return self.Folder .. "/" .. cleanName(name) .. ".json"
	end

	function ConfigManager:_EnsureFolder()
		if self.Capabilities.FileSystem and type(makefolder) == "function" then
			if type(isfolder) ~= "function" or not isfolder(self.Folder) then
				pcall(makefolder, self.Folder)
			end
		end
	end

	function ConfigManager:_Payload()
		return {
			version = 1,
			theme = self.Themes.CurrentName,
			flags = encodeValue(self.Flags:Export()),
			savedAt = os.time(),
		}
	end

	function ConfigManager:ExportConfig()
		return HttpService:JSONEncode(self:_Payload())
	end

	function ConfigManager:ImportConfig(json, options)
		options = options or {}
		local ok, payload = pcall(function()
			return HttpService:JSONDecode(json)
		end)
		if not ok or type(payload) ~= "table" then
			return false, "Invalid config JSON"
		end
		if payload.theme and self.Themes:Get(payload.theme) then
			self.Themes:Set(payload.theme)
		end
		self.Flags:Import(decodeValue(payload.flags or {}), options.Silent == true)
		self.Loaded:Fire(payload)
		return true, payload
	end

	function ConfigManager:SaveConfig(name)
		name = cleanName(name)
		local json = self:ExportConfig()
		self.Memory[name] = json
		if self.Capabilities.FileSystem then
			self:_EnsureFolder()
			local ok, err = pcall(writefile, self:_Path(name), json)
			if not ok then
				return false, err
			end
		end
		self.Saved:Fire(name, json)
		return true, json
	end

	function ConfigManager:LoadConfig(name, options)
		name = cleanName(name)
		local json = self.Memory[name]
		if self.Capabilities.FileSystem and isfile(self:_Path(name)) then
			local ok, result = pcall(readfile, self:_Path(name))
			if not ok then
				return false, result
			end
			json = result
		end
		if not json then
			return false, "Config not found: " .. name
		end
		return self:ImportConfig(json, options)
	end

	function ConfigManager:DeleteConfig(name)
		name = cleanName(name)
		self.Memory[name] = nil
		if self.Capabilities.FileSystem and isfile(self:_Path(name)) then
			if type(delfile) ~= "function" then
				return false, "Executor does not support delfile"
			end
			local ok, err = pcall(delfile, self:_Path(name))
			if not ok then
				return false, err
			end
		end
		return true
	end

	function ConfigManager:ListConfigs()
		local names = {}
		local seen = {}
		for name in pairs(self.Memory) do
			seen[name] = true
			table.insert(names, name)
		end
		if self.Capabilities.FileSystem and type(listfiles) == "function" then
			self:_EnsureFolder()
			local ok, files = pcall(listfiles, self.Folder)
			if ok then
				for _, path in ipairs(files) do
					local name = string.match(path, "([^/\\]+)%.json$")
					if name and not seen[name] then
						seen[name] = true
						table.insert(names, name)
					end
				end
			end
		end
		table.sort(names)
		return names
	end

	function ConfigManager:SetAutoSave(enabled, name, delay)
		self.AutoSave = enabled == true
		self.AutoSaveName = cleanName(name or self.AutoSaveName)
		self.AutoSaveDelay = math.max(0.1, delay or self.AutoSaveDelay)
		return self
	end

	function ConfigManager:_ScheduleAutoSave()
		if not self.AutoSave then
			return
		end
		if self._pendingAutoSave then
			task.cancel(self._pendingAutoSave)
		end
		self._pendingAutoSave = task.delay(self.AutoSaveDelay, function()
			self._pendingAutoSave = nil
			self:SaveConfig(self.AutoSaveName)
		end)
	end

	function ConfigManager:Destroy()
		if self._flagConnection then
			self._flagConnection:Disconnect()
		end
		if self._pendingAutoSave then
			task.cancel(self._pendingAutoSave)
		end
		self.Saved:Destroy()
		self.Loaded:Destroy()
	end

	return ConfigManager
end
]],
	["Managers.EventManager"] = [[
return function(Require)
	local Signal = Require("Utils.Signals")
	local EventManager = {}
	EventManager.__index = EventManager

	function EventManager.new()
		return setmetatable({
			_events = {},
		}, EventManager)
	end

	function EventManager:Get(name)
		if not self._events[name] then
			self._events[name] = Signal.new()
		end
		return self._events[name]
	end

	function EventManager:On(name, callback)
		return self:Get(name):Connect(callback)
	end

	function EventManager:Once(name, callback)
		return self:Get(name):Once(callback)
	end

	function EventManager:Emit(name, ...)
		self:Get(name):Fire(...)
	end

	function EventManager:Destroy()
		for _, signal in pairs(self._events) do
			signal:Destroy()
		end
		table.clear(self._events)
	end

	return EventManager
end
]],
	["Managers.FlagManager"] = [[
return function(Require)
	local Signal = Require("Utils.Signals")
	local FlagManager = {}
	FlagManager.__index = FlagManager

	function FlagManager.new()
		return setmetatable({
			_components = {},
			_values = {},
			Changed = Signal.new(),
		}, FlagManager)
	end

	function FlagManager:Register(flag, component)
		if not flag or flag == "" then
			return
		end
		if self._components[flag] and self._components[flag] ~= component then
			warn("[Astra UI] Flag '" .. flag .. "' was registered more than once")
		end
		self._components[flag] = component
		self._values[flag] = component:GetValue()
	end

	function FlagManager:Unregister(flag, component)
		if self._components[flag] == component then
			self._components[flag] = nil
			self._values[flag] = nil
		end
	end

	function FlagManager:Update(flag, value, source)
		if not flag or flag == "" then
			return
		end
		local previous = self._values[flag]
		self._values[flag] = value
		if previous ~= value then
			self.Changed:Fire(flag, value, previous, source)
		end
	end

	function FlagManager:Get(flag, defaultValue)
		local value = self._values[flag]
		if value == nil then
			return defaultValue
		end
		return value
	end

	function FlagManager:Set(flag, value, silent)
		local component = self._components[flag]
		if component then
			component:SetValue(value, silent)
		else
			self:Update(flag, value)
		end
	end

	function FlagManager:Export()
		return table.clone(self._values)
	end

	function FlagManager:Import(values, silent)
		for flag, value in pairs(values or {}) do
			self:Set(flag, value, silent)
		end
	end

	function FlagManager:Destroy()
		self.Changed:Destroy()
		table.clear(self._components)
		table.clear(self._values)
	end

	return FlagManager
end
]],
	["Managers.StateManager"] = [[
return function(Require)
	local Signal = Require("Utils.Signals")
	local StateManager = {}
	StateManager.__index = StateManager

	function StateManager.new(initialState)
		return setmetatable({
			_values = table.clone(initialState or {}),
			_signals = {},
			Changed = Signal.new(),
		}, StateManager)
	end

	function StateManager:Get(key, defaultValue)
		local value = self._values[key]
		if value == nil then
			return defaultValue
		end
		return value
	end

	function StateManager:Set(key, value)
		local previous = self._values[key]
		if previous == value then
			return value
		end
		self._values[key] = value
		self.Changed:Fire(key, value, previous)
		if self._signals[key] then
			self._signals[key]:Fire(value, previous)
		end
		return value
	end

	function StateManager:Observe(key, callback, fireImmediately)
		if not self._signals[key] then
			self._signals[key] = Signal.new()
		end
		local connection = self._signals[key]:Connect(callback)
		if fireImmediately then
			task.spawn(callback, self._values[key], nil)
		end
		return connection
	end

	function StateManager:Snapshot()
		return table.clone(self._values)
	end

	function StateManager:Destroy()
		self.Changed:Destroy()
		for _, signal in pairs(self._signals) do
			signal:Destroy()
		end
		table.clear(self._signals)
		table.clear(self._values)
	end

	return StateManager
end
]],
	["Managers.ThemeManager"] = [[
return function(Require)
	local Signal = Require("Utils.Signals")
	local ThemeManager = {}
	ThemeManager.__index = ThemeManager

	local requiredTokens = {
		"Background",
		"Surface",
		"SurfaceAlt",
		"SurfaceHover",
		"Accent",
		"AccentAlt",
		"Text",
		"MutedText",
		"Border",
		"Success",
		"Warning",
		"Error",
		"Shadow",
	}

	function ThemeManager.new()
		local self = setmetatable({
			Themes = {},
			Order = {},
			Bindings = setmetatable({}, { __mode = "k" }),
			Changed = Signal.new(),
		}, ThemeManager)

		for _, name in ipairs({
			"Astra",
			"Nebula",
			"Eclipse",
			"SolarFlare",
			"Aurora",
			"Starlight",
			"Dark",
			"Light",
			"Midnight",
			"Crimson",
			"Emerald",
			"Ocean",
			"Purple",
			"Rose",
			"Discord",
			"FluentInspired",
			"RayfieldInspired",
		}) do
			self:Register(name, Require("Themes." .. name))
		end
		self.CurrentName = "Astra"
		self.Current = self.Themes.Astra
		return self
	end

	function ThemeManager:Register(name, theme)
		assert(type(name) == "string" and name ~= "", "Theme name is required")
		assert(type(theme) == "table", "Theme must be a table")
		local base = self.Themes.Astra or self.Themes.Dark
		local normalized = base and table.clone(base) or {}
		for key, value in pairs(theme) do
			normalized[key] = value
		end
		normalized.Name = name
		for _, token in ipairs(requiredTokens) do
			assert(normalized[token] ~= nil, "Theme is missing token: " .. token)
		end
		if not self.Themes[name] then
			table.insert(self.Order, name)
		end
		self.Themes[name] = normalized
		return normalized
	end

	function ThemeManager:Get(name)
		return self.Themes[name or self.CurrentName]
	end

	function ThemeManager:GetNames()
		return table.clone(self.Order)
	end

	function ThemeManager:Bind(instance, propertyMap)
		if not instance then
			return
		end
		self.Bindings[instance] = propertyMap
		self:ApplyTo(instance, propertyMap)
	end

	function ThemeManager:ApplyTo(instance, propertyMap)
		if not instance.Parent and not instance:IsA("ScreenGui") then
			return
		end
		for property, token in pairs(propertyMap) do
			local value = type(token) == "function" and token(self.Current) or self.Current[token]
			if value ~= nil then
				local ok, err = pcall(function()
					instance[property] = value
				end)
				if not ok then
					warn("[Astra UI] Theme binding failed:", err)
				end
			end
		end
	end

	function ThemeManager:Set(theme)
		local resolved
		local name
		if type(theme) == "string" then
			resolved = self.Themes[theme]
			name = theme
		else
			name = theme.Name or "Custom"
			resolved = self:Register(name, theme)
		end
		assert(resolved, "Unknown theme: " .. tostring(theme))
		self.CurrentName = name
		self.Current = resolved
		for instance, propertyMap in pairs(self.Bindings) do
			if instance.Parent then
				self:ApplyTo(instance, propertyMap)
			else
				self.Bindings[instance] = nil
			end
		end
		self.Changed:Fire(resolved, name)
		return resolved
	end

	function ThemeManager:SetAccent(color)
		assert(typeof(color) == "Color3", "Accent must be a Color3")
		local customName = "CustomAccent"
		local custom = table.clone(self.Current)
		custom.Name = customName
		custom.Accent = color
		custom.AccentAlt = color:Lerp(Color3.new(1, 1, 1), 0.28)
		return self:Set(custom)
	end

	function ThemeManager:Destroy()
		self.Changed:Destroy()
		table.clear(self.Bindings)
	end

	return ThemeManager
end
]],
	["Section"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local CleanupManager = Require("Managers.CleanupManager")
	local Button = Require("Components.Button")
	local Toggle = Require("Components.Toggle")
	local Slider = Require("Components.Slider")
	local Dropdown = Require("Components.Dropdown")
	local Input = Require("Components.Input")
	local Keybind = Require("Components.Keybind")
	local ColorPicker = Require("Components.ColorPicker")
	local Paragraph = Require("Components.Paragraph")
	local Divider = Require("Components.Divider")
	local Image = Require("Components.Image")

	local Section = {}
	Section.__index = Section

	function Section.new(tab, options, parent)
		if type(options) == "string" then
			options = { Title = options }
		end
		options = options or {}
		local library = tab.Library
		local root = UI.Create("Frame", {
			AutomaticSize = Enum.AutomaticSize.Y,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			LayoutOrder = tab:_NextOrder(),
			Size = UDim2.new(1, 0, 0, 0),
			Parent = parent or tab.Page,
		})

		local header = UI.Create("TextButton", {
			AutoButtonColor = false,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			LayoutOrder = 0,
			Size = UDim2.new(1, 0, 0, options.Description and 45 or 34),
			Text = "",
			Parent = root,
		})

		local title = UI.Text(options.Title or "Section", 13, Enum.Font.GothamBold)
		title.Position = UDim2.fromOffset(2, 0)
		title.Size = UDim2.new(1, -30, 0, 30)
		title.Parent = header
		library.ThemeManager:Bind(title, { TextColor3 = "Text" })

		local description
		if options.Description then
			description = UI.Text(options.Description, 11, Enum.Font.Gotham)
			description.Position = UDim2.fromOffset(2, 23)
			description.Size = UDim2.new(1, -30, 0, 18)
			description.Parent = header
			library.ThemeManager:Bind(description, { TextColor3 = "MutedText" })
		end

		local chevron = UI.Text("v", 12, Enum.Font.GothamBold)
		chevron.AnchorPoint = Vector2.new(1, 0.5)
		chevron.Position = UDim2.new(1, -3, 0, 17)
		chevron.Size = UDim2.fromOffset(20, 20)
		chevron.TextXAlignment = Enum.TextXAlignment.Center
		chevron.Parent = header
		library.ThemeManager:Bind(chevron, { TextColor3 = "MutedText" })

		local content = UI.Create("Frame", {
			AutomaticSize = Enum.AutomaticSize.Y,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			LayoutOrder = 1,
			Size = UDim2.new(1, 0, 0, 0),
			Parent = root,
		}, {
			UI.List(7),
		})
		UI.List(0).Parent = root

		local self = setmetatable({
			Library = library,
			Tab = tab,
			Options = options,
			Root = root,
			Header = header,
			TitleLabel = title,
			DescriptionLabel = description,
			Chevron = chevron,
			Content = content,
			Components = {},
			Children = {},
			Collapsed = options.Collapsed == true,
			Visible = options.Visible ~= false,
			DependencyVisible = true,
			SearchVisible = true,
			_order = 0,
			Cleanup = CleanupManager.new(),
			Destroyed = false,
		}, Section)

		self.Cleanup:Add(header.MouseButton1Click:Connect(function()
			if options.Collapsible ~= false then
				self:SetCollapsed(not self.Collapsed)
			end
		end))
		self:_BindDependency()
		self:SetCollapsed(self.Collapsed, true)
		if not parent then
			tab:_TrackSection(self)
		end
		return self
	end

	function Section:_NextOrder()
		self._order = self._order + 1
		return self._order
	end

	function Section:_Track(component)
		table.insert(self.Components, component)
		self.Tab:_TrackComponent(component)
		return component
	end

	function Section:_BindDependency()
		local dependency = self.Options.DependsOn
		if type(dependency) ~= "table" then
			self:_RefreshVisibility()
			return
		end
		local function update()
			local value
			if dependency.Component then
				value = dependency.Component:GetValue()
			elseif dependency.Flag then
				value = self.Library.FlagManager:Get(dependency.Flag)
			end
			local passes
			if dependency.Predicate then
				local ok, result = pcall(dependency.Predicate, value)
				passes = ok and result ~= false
			elseif dependency.Value ~= nil then
				passes = value == dependency.Value
			else
				passes = value == true
			end
			self.DependencyVisible = passes
			self:_RefreshVisibility()
		end
		if dependency.Component and dependency.Component.Changed then
			self.Cleanup:Add(dependency.Component.Changed:Connect(update))
		elseif dependency.Flag then
			self.Cleanup:Add(self.Library.FlagManager.Changed:Connect(function(flag)
				if flag == dependency.Flag then
					update()
				end
			end))
		end
		update()
	end

	function Section:_RefreshVisibility()
		self.Root.Visible = self.Visible and self.DependencyVisible and self.SearchVisible
	end

	function Section:AddButton(options)
		return self:_Track(Button.new(self, options))
	end

	function Section:AddToggle(options)
		return self:_Track(Toggle.new(self, options))
	end

	function Section:AddSlider(options)
		return self:_Track(Slider.new(self, options))
	end

	function Section:AddDropdown(options)
		options = options or {}
		options.Multi = false
		return self:_Track(Dropdown.new(self, options))
	end

	function Section:AddMultiDropdown(options)
		options = options or {}
		options.Multi = true
		return self:_Track(Dropdown.new(self, options))
	end

	function Section:AddInput(options)
		return self:_Track(Input.new(self, options))
	end

	function Section:AddKeybind(options)
		return self:_Track(Keybind.new(self, options))
	end

	function Section:AddColorPicker(options)
		return self:_Track(ColorPicker.new(self, options))
	end

	function Section:AddParagraph(options)
		return self:_Track(Paragraph.new(self, options))
	end

	function Section:AddDivider(options)
		return self:_Track(Divider.new(self, options))
	end

	function Section:AddImage(options)
		return self:_Track(Image.new(self, options))
	end

	function Section:AddDependencyBox(options)
		local child = Section.new(self.Tab, options, self.Content)
		table.insert(self.Children, child)
		return child
	end

	function Section:SetCollapsed(collapsed, instant)
		self.Collapsed = collapsed == true
		self.Content.Visible = not self.Collapsed
		self.Chevron.Text = self.Collapsed and ">" or "v"
		if not instant then
			self.Library.AnimationManager:Play(self.Chevron, {
				Rotation = self.Collapsed and -90 or 0,
			}, 0.16)
		end
		return self
	end

	function Section:SetTitle(title)
		self.TitleLabel.Text = tostring(title or "")
		return self
	end

	function Section:SetDescription(description)
		if self.DescriptionLabel then
			self.DescriptionLabel.Text = tostring(description or "")
		end
		return self
	end

	function Section:SetVisible(visible)
		self.Visible = visible == true
		self:_RefreshVisibility()
		return self
	end

	function Section:Hide()
		return self:SetVisible(false)
	end

	function Section:Show()
		return self:SetVisible(true)
	end

	function Section:_Filter(query)
		query = string.lower(query or "")
		local sectionText = string.lower(
			(self.TitleLabel.Text or "") .. " " .. (self.DescriptionLabel and self.DescriptionLabel.Text or "")
		)
		local sectionMatches = query == "" or string.find(sectionText, query, 1, true) ~= nil
		local anyVisible = sectionMatches
		for _, component in ipairs(self.Components) do
			local base = component._base
			if base then
				local text = string.lower((base.Title or "") .. " " .. (base.Description or ""))
				local matches = sectionMatches or query == "" or string.find(text, query, 1, true) ~= nil
				base:_SetSearchVisible(matches)
				anyVisible = anyVisible or matches
			end
		end
		for _, child in ipairs(self.Children) do
			anyVisible = child:_Filter(query) or anyVisible
		end
		self.SearchVisible = anyVisible
		self:_RefreshVisibility()
		return anyVisible
	end

	function Section:Destroy()
		if self.Destroyed then
			return
		end
		self.Destroyed = true
		for index = #self.Components, 1, -1 do
			self.Components[index]:Destroy()
		end
		for index = #self.Children, 1, -1 do
			self.Children[index]:Destroy()
		end
		self.Cleanup:Destroy()
		if self.Root then
			self.Root:Destroy()
			self.Root = nil
		end
	end

	return Section
end
]],
	["Tab"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local Icons = Require("Utils.Icons")
	local CleanupManager = Require("Managers.CleanupManager")
	local Section = Require("Section")
	local Tab = {}
	Tab.__index = Tab

	function Tab.new(window, options)
		if type(options) == "string" then
			options = { Title = options }
		end
		options = options or {}
		local library = window.Library
		local button = UI.Create("TextButton", {
			AutoButtonColor = false,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			LayoutOrder = #window.Tabs + 1,
			Size = UDim2.new(1, 0, 0, 39),
			Text = "",
			Parent = window.TabList,
		}, { UI.Corner(8) })

		local iconData = Icons.Resolve(options.Icon or "Home")
		local iconHolder = UI.Create("Frame", {
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = UDim2.fromOffset(7, 6),
			Size = UDim2.fromOffset(27, 27),
			Parent = button,
		}, {
			UI.Corner(8),
			UI.Stroke(),
		})
		library.ThemeManager:Bind(iconHolder:FindFirstChildOfClass("UIStroke"), { Color = "Border" })
		local icon
		if iconData and iconData.Type == "Image" then
			icon = UI.Create("ImageLabel", {
				BackgroundTransparency = 1,
				Image = iconData.Value,
				Position = UDim2.fromOffset(5, 5),
				Size = UDim2.fromOffset(17, 17),
				Parent = iconHolder,
			})
		else
			icon = UI.Text(iconData and iconData.Value or "", 15, Enum.Font.GothamBold)
			icon.Position = UDim2.fromOffset(2, 1)
			icon.Size = UDim2.fromOffset(23, 24)
			icon.TextXAlignment = Enum.TextXAlignment.Center
			icon.Parent = iconHolder
		end

		local label = UI.Text(options.Title or "Tab", 13, Enum.Font.GothamMedium)
		label.Position = UDim2.fromOffset(43, 0)
		label.Size = UDim2.new(1, -51, 1, 0)
		label.TextTruncate = Enum.TextTruncate.AtEnd
		label.Parent = button
		library.ThemeManager:Bind(label, { TextColor3 = "MutedText" })

		local page = UI.Create("ScrollingFrame", {
			AutomaticCanvasSize = Enum.AutomaticSize.None,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			CanvasSize = UDim2.fromOffset(0, 0),
			ScrollBarImageTransparency = 0.3,
			ScrollBarThickness = 3,
			Size = UDim2.fromScale(1, 1),
			Visible = false,
			Parent = window.Content,
		}, {
			UI.Padding(15, 16, 18, 16),
			UI.List(12),
		})
		library.ThemeManager:Bind(page, { ScrollBarImageColor3 = "Accent" })
		local layout = page:FindFirstChildOfClass("UIListLayout")

		local self = setmetatable({
			Library = library,
			Window = window,
			Options = options,
			Button = button,
			IconHolder = iconHolder,
			Icon = icon,
			Label = label,
			Page = page,
			Layout = layout,
			Sections = {},
			Components = {},
			Active = false,
			Loaded = false,
			LazyLoader = options.Loader,
			_order = 0,
			Cleanup = CleanupManager.new(),
		}, Tab)

		self.Cleanup:Add(UI.SetCanvasFromLayout(page, layout, 34))
		self.Cleanup:Add(button.MouseButton1Click:Connect(function()
			window:SelectTab(self)
		end))
		self.Cleanup:Add(library.ThemeManager.Changed:Connect(function()
			self:_ApplyVisualState()
		end))
		self:_ApplyVisualState()
		return self
	end

	function Tab:_NextOrder()
		self._order = self._order + 1
		return self._order
	end

	function Tab:_TrackSection(section)
		table.insert(self.Sections, section)
	end

	function Tab:_TrackComponent(component)
		table.insert(self.Components, component)
	end

	function Tab:_EnsureLoaded()
		if self.Loaded then
			return
		end
		self.Loaded = true
		if type(self.LazyLoader) == "function" then
			local ok, err = xpcall(function()
				self.LazyLoader(self)
			end, debug.traceback)
			if not ok then
				warn("[Astra UI] Lazy tab loader failed:", err)
			end
		end
	end

	function Tab:SetLazyLoader(loader)
		self.LazyLoader = loader
		self.Loaded = false
		return self
	end

	function Tab:CreateSection(options)
		self:_EnsureLoaded()
		return Section.new(self, options)
	end

	function Tab:AddSection(options)
		return self:CreateSection(options)
	end

	function Tab:_ApplyVisualState()
		local theme = self.Library.ThemeManager.Current
		self.Library.AnimationManager:Play(self.Button, {
			BackgroundTransparency = self.Active and 0 or 1,
			BackgroundColor3 = self.Active and theme.SurfaceHover or theme.Surface,
		}, 0.15)
		self.Library.AnimationManager:Play(self.IconHolder, {
			BackgroundColor3 = self.Active and theme.Accent or theme.SurfaceAlt,
		}, 0.15)
		self.Label.TextColor3 = self.Active and theme.Text or theme.MutedText
		if self.Icon:IsA("TextLabel") then
			self.Icon.TextColor3 = self.Active and theme.Text or theme.AccentAlt
		elseif self.Icon:IsA("ImageLabel") then
			self.Icon.ImageColor3 = self.Active and theme.Text or theme.AccentAlt
		end
	end

	function Tab:_SetActive(active)
		self.Active = active == true
		self.Page.Visible = self.Active
		self:_ApplyVisualState()
		if self.Active then
			self:_EnsureLoaded()
		end
	end

	function Tab:SetSidebarCollapsed(collapsed)
		self.Label.Visible = not collapsed
		self.Button.Size = UDim2.new(1, 0, 0, 39)
		self.IconHolder.Position = collapsed and UDim2.fromOffset(6, 6) or UDim2.fromOffset(7, 6)
	end

	function Tab:Filter(query)
		for _, section in ipairs(self.Sections) do
			section:_Filter(query)
		end
		return self
	end

	function Tab:SetTitle(title)
		self.Label.Text = tostring(title or "")
		return self
	end

	function Tab:SetVisible(visible)
		self.Button.Visible = visible == true
		if not visible and self.Active then
			self.Page.Visible = false
		end
		return self
	end

	function Tab:Hide()
		return self:SetVisible(false)
	end

	function Tab:Show()
		return self:SetVisible(true)
	end

	function Tab:Destroy()
		for index = #self.Sections, 1, -1 do
			self.Sections[index]:Destroy()
		end
		self.Cleanup:Destroy()
		self.Button:Destroy()
		self.Page:Destroy()
	end

	return Tab
end
]],
