	["Utils.Blur"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local Lighting = game:GetService("Lighting")
	local Blur = {}
	Blur.__index = Blur

	function Blur.new(name)
		local self = setmetatable({}, Blur)
		self.Effect = UI.Create("BlurEffect", {
			Name = name or "AstraUIBlur",
			Size = 0,
			Enabled = true,
			Parent = Lighting,
		})
		return self
	end

	function Blur:Set(amount)
		self.Effect.Size = math.clamp(amount or 0, 0, 56)
	end

	function Blur:ApplyAcrylic(frame, theme)
		frame.BackgroundTransparency = theme.AcrylicTransparency or 0.08
		local gradient = UI.Create("UIGradient", {
			Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, theme.Surface),
				ColorSequenceKeypoint.new(1, theme.Background),
			}),
			Rotation = 115,
			Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 0),
				NumberSequenceKeypoint.new(1, 0.12),
			}),
			Parent = frame,
		})
		return gradient
	end

	function Blur:Destroy()
		if self.Effect then
			self.Effect:Destroy()
			self.Effect = nil
		end
	end

	return Blur
end
]],
	["Utils.ExecutorDetection"] = [[
return function()
	local ExecutorDetection = {}

	local function global(name)
		local environment = getgenv and getgenv() or _G
		return environment and environment[name]
	end

	function ExecutorDetection.Detect()
		local name = "Roblox"
		if type(identifyexecutor) == "function" then
			local ok, result = pcall(identifyexecutor)
			if ok and result then
				name = tostring(result)
			end
		elseif type(getexecutorname) == "function" then
			local ok, result = pcall(getexecutorname)
			if ok and result then
				name = tostring(result)
			end
		elseif global("syn") then
			name = "Synapse"
		elseif global("KRNL_LOADED") then
			name = "KRNL"
		end

		return {
			Name = name,
			IsExecutor = name ~= "Roblox",
			FileSystem = type(writefile) == "function"
				and type(readfile) == "function"
				and type(isfile) == "function",
			Clipboard = type(setclipboard) == "function",
			Request = type(request) == "function"
				or type(http_request) == "function"
				or (global("syn") and type(global("syn").request) == "function"),
			ProtectGui = type(protectgui) == "function"
				or (global("syn") and type(global("syn").protect_gui) == "function"),
		}
	end

	return ExecutorDetection
end
]],
	["Utils.Icons"] = [[
return function()
	local Icons = {}

	local glyphs = {
		Astra = "✦",
		Dashboard = "✦",
		Home = "⌂",
		Combat = "⚔",
		Player = "◉",
		User = "◉",
		Visuals = "◇",
		Eye = "◇",
		Theme = "◆",
		Palette = "◆",
		Settings = "⚙",
		Config = "▣",
		Folder = "▣",
		Cloud = "☁",
		Search = "⌕",
		Info = "ⓘ",
		Code = "</>",
		Shield = "⬡",
		Target = "◎",
		Lightning = "ϟ",
		Success = "✓",
		Error = "×",
		Warning = "!",
		Close = "×",
		Minimize = "−",
		Menu = "≡",
		Chevron = "›",
		Check = "✓",
	}

	function Icons.Resolve(icon)
		if type(icon) == "number" then
			return { Type = "Image", Value = "rbxassetid://" .. tostring(icon) }
		end
		if type(icon) == "string" then
			if string.find(icon, "rbxassetid://", 1, true) or string.find(icon, "http", 1, true) then
				return { Type = "Image", Value = icon }
			end
			return { Type = "Text", Value = glyphs[icon] or "✦" }
		end
		return nil
	end

	function Icons.Register(name, value)
		assert(type(name) == "string", "Icon name must be a string")
		glyphs[name] = value
	end

	return Icons
end
]],
	["Utils.Responsive"] = [[
return function()
	local UserInputService = game:GetService("UserInputService")
	local Responsive = {}

	function Responsive.IsMobile()
		return UserInputService.TouchEnabled and not UserInputService.KeyboardEnabled
	end

	function Responsive.GetMode()
		return Responsive.IsMobile() and "Mobile" or "PC"
	end

	function Responsive.Attach(screenGui, callback)
		local camera = workspace.CurrentCamera
		local scale = Instance.new("UIScale")
		scale.Name = "ResponsiveScale"
		scale.Parent = screenGui

		local function update()
			camera = workspace.CurrentCamera or camera
			local viewport = camera and camera.ViewportSize or Vector2.new(1280, 720)
			local base = math.min(viewport.X / 1280, viewport.Y / 720)
			scale.Scale = math.clamp(base, Responsive.IsMobile() and 0.72 or 0.82, 1.15)
			if screenGui:IsA("GuiObject") then
				screenGui.AnchorPoint = Vector2.new(0.5, 0.5)
				screenGui.Position = UDim2.fromScale(0.5, 0.5)
				screenGui.Size = UDim2.fromScale(1 / scale.Scale, 1 / scale.Scale)
			end
			if callback then
				callback(Responsive.GetMode(), viewport, scale.Scale)
			end
		end

		local connection
		if camera then
			connection = camera:GetPropertyChangedSignal("ViewportSize"):Connect(update)
		end
		update()
		return scale, connection
	end

	return Responsive
end
]],
	["Utils.Signals"] = [[
return function()
	local Signal = {}
	Signal.__index = Signal

	local Connection = {}
	Connection.__index = Connection

	function Connection.new(signal, callback)
		return setmetatable({
			Connected = true,
			_signal = signal,
			_callback = callback,
		}, Connection)
	end

	function Connection:Disconnect()
		if not self.Connected then
			return
		end
		self.Connected = false
		self._signal._connections[self] = nil
	end

	function Signal.new()
		return setmetatable({
			_connections = {},
			_waiting = {},
			_destroyed = false,
		}, Signal)
	end

	function Signal:Connect(callback)
		assert(type(callback) == "function", "Signal:Connect expects a function")
		assert(not self._destroyed, "Cannot connect to a destroyed signal")
		local connection = Connection.new(self, callback)
		self._connections[connection] = true
		return connection
	end

	function Signal:Once(callback)
		local connection
		connection = self:Connect(function(...)
			connection:Disconnect()
			callback(...)
		end)
		return connection
	end

	function Signal:Fire(...)
		if self._destroyed then
			return
		end
		local arguments = table.pack(...)
		for connection in pairs(self._connections) do
			if connection.Connected then
				task.spawn(connection._callback, table.unpack(arguments, 1, arguments.n))
			end
		end
		for thread in pairs(self._waiting) do
			self._waiting[thread] = nil
			task.spawn(thread, table.unpack(arguments, 1, arguments.n))
		end
	end

	function Signal:Wait()
		assert(not self._destroyed, "Cannot wait on a destroyed signal")
		local thread = coroutine.running()
		self._waiting[thread] = true
		return coroutine.yield()
	end

	function Signal:Destroy()
		self._destroyed = true
		for connection in pairs(self._connections) do
			connection:Disconnect()
		end
		for thread in pairs(self._waiting) do
			task.cancel(thread)
		end
		table.clear(self._connections)
		table.clear(self._waiting)
	end

	return Signal
end
]],
	["Utils.Tween"] = [[
return function()
	local TweenService = game:GetService("TweenService")
	local active = setmetatable({}, { __mode = "k" })
	local Tween = {}

	function Tween.Play(instance, properties, duration, style, direction)
		local previous = active[instance]
		if previous then
			previous:Cancel()
		end
		local tween = TweenService:Create(
			instance,
			TweenInfo.new(
				duration or 0.2,
				style or Enum.EasingStyle.Quint,
				direction or Enum.EasingDirection.Out
			),
			properties
		)
		active[instance] = tween
		tween.Completed:Once(function()
			if active[instance] == tween then
				active[instance] = nil
			end
		end)
		tween:Play()
		return tween
	end

	function Tween.Cancel(instance)
		local tween = active[instance]
		if tween then
			tween:Cancel()
			active[instance] = nil
		end
	end

	function Tween.Hover(button, normalColor, hoverColor)
		local enter = button.MouseEnter:Connect(function()
			Tween.Play(button, { BackgroundColor3 = hoverColor }, 0.14)
		end)
		local leave = button.MouseLeave:Connect(function()
			Tween.Play(button, { BackgroundColor3 = normalColor }, 0.14)
		end)
		return { enter, leave }
	end

	return Tween
end
]],
	["Utils.UI"] = [[
return function()
	local UI = {}

	function UI.Create(className, properties, children)
		local instance = Instance.new(className)
		for property, value in pairs(properties or {}) do
			instance[property] = value
		end
		for _, child in ipairs(children or {}) do
			child.Parent = instance
		end
		return instance
	end

	function UI.Corner(radius)
		return UI.Create("UICorner", {
			CornerRadius = UDim.new(0, radius or 8),
		})
	end

	function UI.Stroke(color, transparency, thickness)
		return UI.Create("UIStroke", {
			Color = color or Color3.new(1, 1, 1),
			Transparency = transparency or 0,
			Thickness = thickness or 1,
			ApplyStrokeMode = Enum.ApplyStrokeMode.Border,
		})
	end

	function UI.Padding(top, right, bottom, left)
		return UI.Create("UIPadding", {
			PaddingTop = UDim.new(0, top or 0),
			PaddingRight = UDim.new(0, right or top or 0),
			PaddingBottom = UDim.new(0, bottom or top or 0),
			PaddingLeft = UDim.new(0, left or right or top or 0),
		})
	end

	function UI.List(spacing, horizontal)
		return UI.Create("UIListLayout", {
			Padding = UDim.new(0, spacing or 0),
			FillDirection = horizontal and Enum.FillDirection.Horizontal or Enum.FillDirection.Vertical,
			HorizontalAlignment = Enum.HorizontalAlignment.Left,
			VerticalAlignment = Enum.VerticalAlignment.Top,
			SortOrder = Enum.SortOrder.LayoutOrder,
		})
	end

	function UI.Text(text, size, font)
		return UI.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Font = font or Enum.Font.Gotham,
			Text = text or "",
			TextSize = size or 14,
			TextWrapped = true,
			TextXAlignment = Enum.TextXAlignment.Left,
			TextYAlignment = Enum.TextYAlignment.Center,
		})
	end

	function UI.Button(text)
		return UI.Create("TextButton", {
			AutoButtonColor = false,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Font = Enum.Font.GothamMedium,
			Text = text or "",
			TextSize = 14,
		})
	end

	function UI.SetCanvasFromLayout(scroller, layout, padding)
		local function update()
			scroller.CanvasSize = UDim2.fromOffset(0, layout.AbsoluteContentSize.Y + (padding or 0))
		end
		local connection = layout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(update)
		update()
		return connection
	end

	function UI.ClampToViewport(frame, viewport, margin)
		margin = margin or 8
		local size = frame.AbsoluteSize
		local position = frame.AbsolutePosition
		local x = math.clamp(position.X, margin, math.max(margin, viewport.X - size.X - margin))
		local y = math.clamp(position.Y, margin, math.max(margin, viewport.Y - size.Y - margin))
		frame.Position = UDim2.fromOffset(x, y)
	end

	function UI.SafeCallback(callback, ...)
		if type(callback) ~= "function" then
			return true
		end
		local arguments = table.pack(...)
		return xpcall(function()
			callback(table.unpack(arguments, 1, arguments.n))
		end, warn)
	end

	return UI
end
]],
	["Window"] = [[
return function(Require)
	local UI = Require("Utils.UI")
	local Icons = Require("Utils.Icons")
	local CleanupManager = Require("Managers.CleanupManager")
	local Tab = Require("Tab")
	local UserInputService = game:GetService("UserInputService")
	local Window = {}
	Window.__index = Window

	local function isPrimaryInput(input)
		return input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch
	end

	function Window.new(library, options)
		options = options or {}
		local size = options.Size or UDim2.fromOffset(700, 470)
		local position = options.Position or UDim2.fromScale(0.5, 0.5)

		local shadow = UI.Create("Frame", {
			AnchorPoint = Vector2.new(0.5, 0.5),
			BackgroundTransparency = 0.63,
			BorderSizePixel = 0,
			Position = UDim2.new(position.X.Scale, position.X.Offset + 8, position.Y.Scale, position.Y.Offset + 11),
			Size = UDim2.new(size.X.Scale, size.X.Offset + 20, size.Y.Scale, size.Y.Offset + 24),
			ZIndex = options.ZIndex or 10,
			Parent = library.WindowLayer,
		}, { UI.Corner(18) })
		library.ThemeManager:Bind(shadow, { BackgroundColor3 = "Shadow" })

		local frame = UI.Create("Frame", {
			AnchorPoint = Vector2.new(0.5, 0.5),
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			ClipsDescendants = true,
			Position = position,
			Size = size,
			ZIndex = (options.ZIndex or 10) + 1,
			Parent = library.WindowLayer,
		}, {
			UI.Corner(options.CornerRadius or 13),
			UI.Stroke(),
		})
		library.ThemeManager:Bind(frame, { BackgroundColor3 = "Background" })
		library.ThemeManager:Bind(frame:FindFirstChildOfClass("UIStroke"), { Color = "Border" })
		if options.Acrylic ~= false then
			local acrylicGradient = library.Blur:ApplyAcrylic(frame, library.ThemeManager.Current)
			library.ThemeManager:Bind(acrylicGradient, {
				Color = function(theme)
					return ColorSequence.new({
						ColorSequenceKeypoint.new(0, theme.Surface),
						ColorSequenceKeypoint.new(1, theme.Background),
					})
				end,
			})
			library:_AcquireBlur()
		end

		local topbar = UI.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 56),
			ZIndex = frame.ZIndex + 1,
			Parent = frame,
		})
		local brand = UI.Create("Frame", {
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = UDim2.fromOffset(14, 10),
			Size = UDim2.fromOffset(36, 36),
			Parent = topbar,
		}, {
			UI.Corner(11),
			UI.Stroke(),
			UI.Create("UIGradient", {
				Rotation = 45,
			}),
		})
		library.ThemeManager:Bind(brand, { BackgroundColor3 = "Accent" })
		library.ThemeManager:Bind(brand:FindFirstChildOfClass("UIStroke"), { Color = "AccentAlt" })
		library.ThemeManager:Bind(brand:FindFirstChildOfClass("UIGradient"), {
			Color = function(theme)
				return ColorSequence.new(theme.Accent, theme.AccentAlt)
			end,
		})
		local brandStar = UI.Text("✦", 21, Enum.Font.GothamBold)
		brandStar.Size = UDim2.fromScale(1, 1)
		brandStar.TextXAlignment = Enum.TextXAlignment.Center
		brandStar.Parent = brand
		library.ThemeManager:Bind(brandStar, { TextColor3 = "Text" })

		local title = UI.Text(options.Title or "Astra UI", 17, Enum.Font.GothamBold)
		title.Position = UDim2.fromOffset(59, 8)
		title.Size = UDim2.new(1, -211, 0, 24)
		title.Parent = topbar
		library.ThemeManager:Bind(title, { TextColor3 = "Text" })
		local subtitle = UI.Text(options.Subtitle or "Explore beyond the ordinary", 11, Enum.Font.Gotham)
		subtitle.Position = UDim2.fromOffset(59, 31)
		subtitle.Size = UDim2.new(1, -211, 0, 17)
		subtitle.Parent = topbar
		library.ThemeManager:Bind(subtitle, { TextColor3 = "MutedText" })

		local controls = UI.Create("Frame", {
			AnchorPoint = Vector2.new(1, 0),
			BackgroundTransparency = 1,
			Position = UDim2.new(1, -10, 0, 10),
			Size = UDim2.fromOffset(112, 34),
			Parent = topbar,
		}, {
			UI.Create("UIListLayout", {
				FillDirection = Enum.FillDirection.Horizontal,
				HorizontalAlignment = Enum.HorizontalAlignment.Right,
				Padding = UDim.new(0, 5),
				SortOrder = Enum.SortOrder.LayoutOrder,
			}),
		})

		local function controlButton(text, order)
			local button = UI.Create("TextButton", {
				AutoButtonColor = false,
				BackgroundTransparency = 0,
				BorderSizePixel = 0,
				Font = Enum.Font.GothamBold,
				LayoutOrder = order,
				Size = UDim2.fromOffset(32, 32),
				Text = text,
				TextSize = 12,
				Parent = controls,
			}, { UI.Corner(7) })
			library.ThemeManager:Bind(button, {
				BackgroundColor3 = "SurfaceAlt",
				TextColor3 = "MutedText",
			})
			return button
		end

		local menuButton = controlButton(Icons.Resolve("Menu").Value, 1)
		local minimizeButton = controlButton(Icons.Resolve("Minimize").Value, 2)
		local closeButton = controlButton(Icons.Resolve("Close").Value, 3)

		local body = UI.Create("Frame", {
			BackgroundTransparency = 1,
			Position = UDim2.fromOffset(0, 56),
			Size = UDim2.new(1, 0, 1, -56),
			Parent = frame,
		})
		local topbarLine = UI.Create("Frame", {
			AnchorPoint = Vector2.new(0, 1),
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = UDim2.new(0, 0, 1, 0),
			Size = UDim2.new(1, 0, 0, 1),
			Parent = topbar,
		})
		library.ThemeManager:Bind(topbarLine, { BackgroundColor3 = "Border" })

		local sidebar = UI.Create("Frame", {
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Size = UDim2.new(0, 190, 1, 0),
			Parent = body,
		})
		library.ThemeManager:Bind(sidebar, { BackgroundColor3 = "Surface" })

		local search = UI.Create("TextBox", {
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			ClearTextOnFocus = false,
			Font = Enum.Font.Gotham,
			PlaceholderText = options.SearchPlaceholder or "Search Astra...",
			Position = UDim2.fromOffset(10, 9),
			Size = UDim2.new(1, -20, 0, 34),
			Text = "",
			TextSize = 12,
			TextXAlignment = Enum.TextXAlignment.Left,
			Parent = sidebar,
		}, {
			UI.Corner(8),
			UI.Stroke(),
			UI.Padding(0, 10, 0, 10),
		})
		library.ThemeManager:Bind(search, {
			BackgroundColor3 = "SurfaceAlt",
			PlaceholderColor3 = "MutedText",
			TextColor3 = "Text",
		})
		library.ThemeManager:Bind(search:FindFirstChildOfClass("UIStroke"), { Color = "Border" })

		local tabList = UI.Create("ScrollingFrame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			CanvasSize = UDim2.fromOffset(0, 0),
			Position = UDim2.fromOffset(10, 52),
			ScrollBarThickness = 0,
			Size = UDim2.new(1, -20, 1, -62),
			Parent = sidebar,
		}, { UI.List(6) })
		local tabLayout = tabList:FindFirstChildOfClass("UIListLayout")

		local content = UI.Create("Frame", {
			BackgroundTransparency = 1,
			Position = UDim2.fromOffset(190, 0),
			Size = UDim2.new(1, -190, 1, 0),
			Parent = body,
		})

		local resizeHandle = UI.Create("TextButton", {
			AnchorPoint = Vector2.new(1, 1),
			AutoButtonColor = false,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Position = UDim2.fromScale(1, 1),
			Size = UDim2.fromOffset(22, 22),
			Text = "",
			ZIndex = frame.ZIndex + 4,
			Parent = frame,
		})
		local resizeMark = UI.Create("Frame", {
			AnchorPoint = Vector2.new(1, 1),
			BackgroundTransparency = 0,
			BorderSizePixel = 0,
			Position = UDim2.new(1, -5, 1, -5),
			Rotation = -45,
			Size = UDim2.fromOffset(11, 2),
			Parent = resizeHandle,
		})
		library.ThemeManager:Bind(resizeMark, { BackgroundColor3 = "MutedText" })

		local self = setmetatable({
			Library = library,
			Options = options,
			Frame = frame,
			Shadow = shadow,
			Topbar = topbar,
			Body = body,
			Sidebar = sidebar,
			SearchBox = search,
			TabList = tabList,
			Content = content,
			TitleLabel = title,
			SubtitleLabel = subtitle,
			Tabs = {},
			ActiveTab = nil,
			Visible = true,
			Minimized = false,
			SidebarCollapsed = false,
			Closed = false,
			NormalSize = size,
			_BlurActive = options.Acrylic ~= false,
			Cleanup = CleanupManager.new(),
		}, Window)

		self.Cleanup:Add(UI.SetCanvasFromLayout(tabList, tabLayout, 12))
		self.Cleanup:Add(menuButton.MouseButton1Click:Connect(function()
			self:SetSidebarCollapsed(not self.SidebarCollapsed)
		end))
		self.Cleanup:Add(minimizeButton.MouseButton1Click:Connect(function()
			self:SetMinimized(not self.Minimized)
		end))
		self.Cleanup:Add(closeButton.MouseButton1Click:Connect(function()
			if options.DestroyOnClose then
				self:Destroy()
			else
				self:Hide()
			end
		end))
		self.Cleanup:Add(search:GetPropertyChangedSignal("Text"):Connect(function()
			if self.ActiveTab then
				self.ActiveTab:Filter(search.Text)
			end
		end))

		self:_BindDragging()
		self:_BindResizing(resizeHandle)
		self:_BindToggleKey(options.Keybind or Enum.KeyCode.RightControl)
		self:_BindFocus()
		if library.Mode == "Mobile" then
			resizeHandle.Visible = false
			self.Frame.Size = options.MobileSize or UDim2.new(0.92, 0, 0.78, 0)
			self.Frame.Position = UDim2.fromScale(0.5, 0.5)
			self.Shadow.Visible = false
		end
		return self
	end

	function Window:_BindFocus()
		self.Cleanup:Add(self.Frame.InputBegan:Connect(function(input)
			if isPrimaryInput(input) then
				self.Library:_FocusWindow(self)
			end
		end))
	end

	function Window:_SyncShadow()
		self.Shadow.Position = UDim2.new(
			self.Frame.Position.X.Scale,
			self.Frame.Position.X.Offset + 8,
			self.Frame.Position.Y.Scale,
			self.Frame.Position.Y.Offset + 11
		)
		self.Shadow.Size = UDim2.new(
			self.Frame.Size.X.Scale,
			self.Frame.Size.X.Offset + 20,
			self.Frame.Size.Y.Scale,
			self.Frame.Size.Y.Offset + 24
		)
	end

	function Window:_BindDragging()
		local dragging = false
		local startInput
		local startPosition
		self.Cleanup:Add(self.Topbar.InputBegan:Connect(function(input)
			if isPrimaryInput(input) then
				dragging = true
				startInput = input.Position
				startPosition = self.Frame.Position
				self.Library:_FocusWindow(self)
			end
		end))
		self.Cleanup:Add(UserInputService.InputChanged:Connect(function(input)
			if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch) then
				local delta = input.Position - startInput
				self.Frame.Position = UDim2.new(
					startPosition.X.Scale,
					startPosition.X.Offset + delta.X,
					startPosition.Y.Scale,
					startPosition.Y.Offset + delta.Y
				)
				self:_SyncShadow()
			end
		end))
		self.Cleanup:Add(UserInputService.InputEnded:Connect(function(input)
			if isPrimaryInput(input) then
				dragging = false
			end
		end))
	end

	function Window:_BindResizing(handle)
		local resizing = false
		local startInput
		local startSize
		local minimum = self.Options.MinimumSize or Vector2.new(520, 340)
		local maximum = self.Options.MaximumSize or Vector2.new(1100, 800)
		self.Cleanup:Add(handle.InputBegan:Connect(function(input)
			if isPrimaryInput(input) and not self.Minimized then
				resizing = true
				startInput = input.Position
				startSize = self.Frame.AbsoluteSize
			end
		end))
		self.Cleanup:Add(UserInputService.InputChanged:Connect(function(input)
			if resizing and (input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch) then
				local delta = input.Position - startInput
				local width = math.clamp(startSize.X + delta.X, minimum.X, maximum.X)
				local height = math.clamp(startSize.Y + delta.Y, minimum.Y, maximum.Y)
				self.Frame.Size = UDim2.fromOffset(width, height)
				self.NormalSize = self.Frame.Size
				self:_SyncShadow()
			end
		end))
		self.Cleanup:Add(UserInputService.InputEnded:Connect(function(input)
			if isPrimaryInput(input) then
				resizing = false
			end
		end))
	end

	function Window:_BindToggleKey(keybind)
		self.ToggleKey = keybind
		self.Cleanup:Add(UserInputService.InputBegan:Connect(function(input, processed)
			if not processed and input.KeyCode == self.ToggleKey then
				self:SetVisible(not self.Visible)
			end
		end))
	end

	function Window:CreateTab(options)
		local tab = Tab.new(self, options)
		table.insert(self.Tabs, tab)
		if not self.ActiveTab then
			self:SelectTab(tab)
		end
		return tab
	end

	function Window:AddTab(options)
		return self:CreateTab(options)
	end

	function Window:SelectTab(tab)
		if self.ActiveTab == tab then
			return self
		end
		for _, candidate in ipairs(self.Tabs) do
			candidate:_SetActive(candidate == tab)
		end
		self.ActiveTab = tab
		tab:Filter(self.SearchBox.Text)
		return self
	end

	function Window:SetSidebarCollapsed(collapsed)
		self.SidebarCollapsed = collapsed == true
		local width = self.SidebarCollapsed and 58 or 190
		self.SearchBox.Visible = not self.SidebarCollapsed
		self.TabList.Position = UDim2.fromOffset(self.SidebarCollapsed and 8 or 10, self.SidebarCollapsed and 10 or 52)
		self.TabList.Size = UDim2.new(1, self.SidebarCollapsed and -16 or -20, 1, self.SidebarCollapsed and -20 or -62)
		for _, tab in ipairs(self.Tabs) do
			tab:SetSidebarCollapsed(self.SidebarCollapsed)
		end
		self.Library.AnimationManager:Play(self.Sidebar, { Size = UDim2.new(0, width, 1, 0) }, 0.2)
		self.Library.AnimationManager:Play(self.Content, {
			Position = UDim2.fromOffset(width, 0),
			Size = UDim2.new(1, -width, 1, 0),
		}, 0.2)
		return self
	end

	function Window:SetMinimized(minimized)
		self.Minimized = minimized == true
		if self.Minimized then
			self.NormalSize = self.Frame.Size
		end
		self.Body.Visible = not self.Minimized
		self.Library.AnimationManager:Play(self.Frame, {
			Size = self.Minimized and UDim2.new(self.NormalSize.X.Scale, self.NormalSize.X.Offset, 0, 56)
				or self.NormalSize,
		}, 0.22)
		task.delay(0.23, function()
			if self.Frame and self.Frame.Parent then
				self:_SyncShadow()
			end
		end)
		return self
	end

	function Window:SetVisible(visible)
		visible = visible == true
		if self.Visible == visible then
			return self
		end
		self.Visible = visible
		self.Frame.Visible = self.Visible
		self.Shadow.Visible = self.Visible and self.Library.Mode ~= "Mobile"
		if self.Options.Acrylic ~= false then
			if self.Visible and not self._BlurActive then
				self._BlurActive = true
				self.Library:_AcquireBlur()
			elseif not self.Visible and self._BlurActive then
				self._BlurActive = false
				self.Library:_ReleaseBlur()
			end
		end
		return self
	end

	function Window:Hide()
		return self:SetVisible(false)
	end

	function Window:Show()
		return self:SetVisible(true)
	end

	function Window:SetTitle(title)
		self.TitleLabel.Text = tostring(title or "")
		return self
	end

	function Window:SetDescription(description)
		self.SubtitleLabel.Text = tostring(description or "")
		return self
	end

	function Window:SetKeybind(keybind)
		self.ToggleKey = keybind
		return self
	end

	function Window:Destroy()
		if self.Closed then
			return
		end
		self.Closed = true
		for index = #self.Tabs, 1, -1 do
			self.Tabs[index]:Destroy()
		end
		self.Cleanup:Destroy()
		if self._BlurActive then
			self._BlurActive = false
			self.Library:_ReleaseBlur()
		end
		self.Frame:Destroy()
		self.Shadow:Destroy()
		self.Library:_RemoveWindow(self)
	end

	return Window
end
]],
}

local cache = {}
local loading = {}

local function Require(name)
	if cache[name] ~= nil then
		return cache[name]
	end
	assert(not loading[name], "Circular module dependency: " .. tostring(name))
	local source = moduleSources[name]
	assert(source, "Unknown Astra UI module: " .. tostring(name))
	loading[name] = true
	local chunk, compileError = loadstring(source, "@AstraUI/" .. name)
	assert(chunk, compileError)
	local ok, factory = xpcall(chunk, debug.traceback)
	assert(ok, factory)
	local result = type(factory) == "function" and factory(Require) or factory
	cache[name] = result
	loading[name] = nil
	return result
end

local LibraryClass = Require("Library")
local defaultInstance
local export = { Version = LibraryClass.Version }

function export.new(first, second)
	local options = first == export and second or first
	return LibraryClass.new(options)
end

setmetatable(export, {
	__index = function(_, key)
		defaultInstance = defaultInstance or LibraryClass.new()
		local value = defaultInstance[key]
		if type(value) == "function" then
			return function(first, ...)
				if first == export then
					return value(defaultInstance, ...)
				end
				return value(defaultInstance, first, ...)
			end
		end
		return value
	end,
})

return export
